import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { Lock, Eye, Eraser, Clock, Shield, Play, Pause } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
  isOwn: boolean;
}

export const MessageBubble: React.FC<MessageBubbleProps> = ({ message, isOwn }) => {
  const [isRevealed, setIsRevealed] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [unlockError, setUnlockError] = useState(false);
  const [timeLeft, setTimeLeft] = useState<string>('');
  const [isUnlocked, setIsUnlocked] = useState(false);

  // Scratch card refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scratchContainerRef = useRef<HTMLDivElement>(null);
  const [isScratched, setIsScratched] = useState(false);

  // Time capsule effect
  useEffect(() => {
    if (message.type === 'capsule' && message.meta?.unlockTime) {
      const interval = setInterval(() => {
        const now = new Date().getTime();
        const unlock = new Date(message.meta!.unlockTime!).getTime();
        const diff = unlock - now;

        if (diff <= 0) {
          setIsUnlocked(true);
          clearInterval(interval);
        } else {
          const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
          const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
          const seconds = Math.floor((diff % (1000 * 60)) / 1000);
          setTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
        }
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [message]);

  // Scratch card setup
  useEffect(() => {
    if (message.type === 'scratch' && canvasRef.current && scratchContainerRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = scratchContainerRef.current.clientWidth;
      canvas.height = scratchContainerRef.current.clientHeight;

      // Fill with scratch layer
      ctx.fillStyle = '#475569'; // Slate-600
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Add text/pattern
      ctx.fillStyle = '#94a3b8';
      ctx.font = '14px Rajdhani';
      ctx.fillText("SCRATCH TO REVEAL", 20, canvas.height / 2);

      const handleMove = (e: MouseEvent | TouchEvent) => {
        const rect = canvas.getBoundingClientRect();
        let x, y;
        if ('touches' in e) {
          x = e.touches[0].clientX - rect.left;
          y = e.touches[0].clientY - rect.top;
        } else {
          x = (e as MouseEvent).clientX - rect.left;
          y = (e as MouseEvent).clientY - rect.top;
        }

        ctx.globalCompositeOperation = 'destination-out';
        ctx.beginPath();
        ctx.arc(x, y, 15, 0, 2 * Math.PI);
        ctx.fill();

        // Check completion (simplified)
        // In real app, check pixel data
      };

      canvas.addEventListener('mousemove', handleMove);
      canvas.addEventListener('touchmove', handleMove);

      return () => {
        canvas.removeEventListener('mousemove', handleMove);
        canvas.removeEventListener('touchmove', handleMove);
      };
    }
  }, [message.type]);

  const handleUnlock = () => {
    if (passwordInput === (message.meta?.password || '1234')) {
      setIsUnlocked(true);
      setUnlockError(false);
    } else {
      setUnlockError(true);
    }
  };

  const baseClasses = `max-w-[80%] rounded-2xl p-4 mb-4 relative transition-all duration-300 ${
    isOwn 
      ? 'bg-gradient-to-br from-violet-600/90 to-cyan-600/90 text-white ml-auto rounded-tr-none shadow-[0_0_15px_rgba(139,92,246,0.2)]' 
      : 'bg-slate-800/80 backdrop-blur-md text-slate-200 rounded-tl-none border border-white/5'
  }`;

  // Content Rendering Logic
  const renderContent = () => {
    switch (message.type) {
      case 'stealth':
        return (
          <div className="group relative cursor-help">
            <div className="absolute inset-0 bg-black/50 blur-sm group-hover:opacity-0 transition-opacity duration-500 rounded-lg flex items-center justify-center">
               <Shield size={16} className="text-slate-400" />
            </div>
            <p className={`opacity-0 group-hover:opacity-100 transition-opacity duration-300 ${isOwn ? 'text-white' : 'text-slate-200'} blur-md group-hover:blur-0`}>
              {message.content}
            </p>
          </div>
        );

      case 'scratch':
        return (
          <div ref={scratchContainerRef} className="relative min-h-[60px] min-w-[200px] flex items-center justify-center overflow-hidden rounded-lg">
             <div className="select-none font-bold text-lg">{message.content}</div>
             <canvas 
              ref={canvasRef} 
              className="absolute inset-0 touch-none cursor-crosshair"
             />
          </div>
        );

      case 'capsule':
        if (isUnlocked) {
          return (
            <div className="animate-fade-in">
               <div className="flex items-center gap-2 text-xs text-green-300 mb-1">
                 <Clock size={12} /> UNLOCKED
               </div>
               <p>{message.content}</p>
            </div>
          );
        }
        return (
          <div className="flex flex-col items-center justify-center p-2 min-w-[150px]">
            <Clock className="animate-pulse text-cyan-400 mb-2" />
            <span className="font-mono text-xl font-bold tracking-widest">{timeLeft}</span>
            <span className="text-[10px] uppercase text-slate-400 mt-1">LOCKED UNTIL REVEAL</span>
          </div>
        );

      case 'lock':
        if (isUnlocked) {
           return <p>{message.content}</p>;
        }
        return (
          <div className="flex flex-col gap-2 min-w-[200px]">
            <div className="flex items-center gap-2 text-yellow-500 mb-1">
              <Lock size={16} />
              <span className="text-xs uppercase font-bold">Encrypted Message</span>
            </div>
            <input 
              type="password" 
              placeholder="Enter Key" 
              value={passwordInput}
              onChange={(e) => setPasswordInput(e.target.value)}
              className="bg-black/30 border border-white/10 rounded px-2 py-1 text-sm focus:border-cyan-400 outline-none w-full"
            />
            <button 
              onClick={handleUnlock}
              className="bg-white/10 hover:bg-white/20 text-xs py-1 rounded transition-colors"
            >
              DECRYPT
            </button>
            {unlockError && <span className="text-[10px] text-red-400">Invalid Key Code</span>}
          </div>
        );

      case 'draw':
        return (
          <div className="rounded-lg overflow-hidden border border-white/10 bg-white/5">
            <img src={message.content} alt="Drawing" className="max-w-full h-auto" />
          </div>
        );

      case 'image':
        return (
          <div className="rounded-lg overflow-hidden border border-white/10">
             <img src={message.content} alt="User sent" className="max-w-full h-auto" />
          </div>
        );

      default:
        return <p className="whitespace-pre-wrap">{message.content}</p>;
    }
  };

  return (
    <div className={baseClasses}>
      {renderContent()}
      <div className={`text-[10px] mt-2 opacity-50 flex justify-end gap-1 ${isOwn ? 'text-white' : 'text-slate-400'}`}>
        <span>{new Date(message.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { ChatSession, User, Message, MessageType } from '../types';
import { MessageBubble } from './MessageBubble';
import { Toolbox } from './Toolbox';
import { Phone, Video, MoreHorizontal, ArrowLeft } from 'lucide-react';
import { generateAiResponse } from '../services/geminiService';

interface ChatAreaProps {
  session: ChatSession | null;
  currentUser: User;
  onSendMessage: (sessionId: string, message: Partial<Message>) => void;
  onBack: () => void;
  isMobile: boolean;
}

export const ChatArea: React.FC<ChatAreaProps> = ({ session, currentUser, onSendMessage, onBack, isMobile }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isNudged, setIsNudged] = useState(false);
  const [isTyping, setIsTyping] = useState(false);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session?.messages]);

  // Handle Nudge Effect
  useEffect(() => {
    if (session?.lastMessage?.type === 'nudge') {
      setIsNudged(true);
      const timer = setTimeout(() => setIsNudged(false), 500);
      return () => clearTimeout(timer);
    }
  }, [session?.lastMessage]);

  // AI Response Handler
  useEffect(() => {
    if (session && session.messages.length > 0) {
       const lastMsg = session.messages[session.messages.length - 1];
       const otherParticipant = session.participants.find(p => p.id !== currentUser.id);

       if (otherParticipant?.isAi && lastMsg.senderId === currentUser.id && lastMsg.type === 'text') {
         setIsTyping(true);

         const history = session.messages
          .filter(m => m.type === 'text')
          .slice(-10) // Context window
          .map(m => ({
             role: m.senderId === currentUser.id ? 'user' : 'model',
             parts: [{ text: m.content }]
          }));
         // Remove the very last one as it's the new prompt
         const prompt = history.pop()?.parts[0].text || "";

         generateAiResponse(prompt, history).then(text => {
             onSendMessage(session.id, {
                 type: 'text',
                 content: text,
                 senderId: otherParticipant.id // AI sends it
             });
             setIsTyping(false);
         });
       }
    }
  }, [session?.messages, currentUser.id, session?.participants]);

  if (!session) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-cyber-dark text-slate-500">
         <div className="w-24 h-24 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center mb-4 shadow-[0_0_30px_rgba(6,182,212,0.1)]">
            <span className="text-4xl">👋</span>
         </div>
         <p>Select a frequency to begin transmission.</p>
      </div>
    );
  }

  const otherUser = session.participants.find(p => p.id !== currentUser.id) || session.participants[0];

  return (
    <div className={`flex-1 flex flex-col bg-cyber-dark relative overflow-hidden ${isNudged ? 'animate-shake' : ''}`}>
       {/* Background Grid */}
       <div className="absolute inset-0 opacity-10 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none"></div>

       {/* Header */}
       <div className="relative z-10 p-4 border-b border-white/5 bg-cyber-panel/80 backdrop-blur-md flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
             {isMobile && (
               <button onClick={onBack} className="md:hidden text-slate-400 hover:text-white">
                 <ArrowLeft />
               </button>
             )}
             <img src={otherUser.avatar} className="w-10 h-10 rounded-full border border-cyan-500" alt={otherUser.name} />
             <div>
               <h3 className="font-bold text-white flex items-center gap-2">
                 {otherUser.name}
                 {otherUser.isAi && <span className="bg-violet-600 text-[10px] px-1 rounded">AI</span>}
               </h3>
               <span className="text-xs text-cyan-400">{isTyping ? 'Computing...' : otherUser.status}</span>
             </div>
          </div>
          <div className="flex gap-4 text-slate-400">
             <button className="hover:text-cyan-400 transition-colors"><Phone size={20} /></button>
             <button className="hover:text-cyan-400 transition-colors"><Video size={20} /></button>
             <button className="hover:text-cyan-400 transition-colors"><MoreHorizontal size={20} /></button>
          </div>
       </div>

       {/* Messages */}
       <div className="flex-1 overflow-y-auto p-4 space-y-2 relative z-10" ref={scrollRef}>
          {session.messages.map((msg) => (
             <MessageBubble 
               key={msg.id} 
               message={msg} 
               isOwn={msg.senderId === currentUser.id} 
             />
          ))}
          {isTyping && (
             <div className="max-w-[100px] bg-slate-800/80 p-3 rounded-2xl rounded-tl-none flex items-center gap-1">
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-150"></div>
             </div>
          )}
       </div>

       {/* Composer */}
       <Toolbox 
         onSend={(msg) => onSendMessage(session.id, { ...msg, senderId: currentUser.id })} 
       />
    </div>
  );
};

import React, { useState } from 'react';
import { Send, EyeOff, Eraser, Clock, Lock, PenTool, Mic, Gamepad2, X, Paperclip, Smile } from 'lucide-react';
import { MessageType } from '../types';
import { DrawModal } from './DrawModal';

interface ToolboxProps {
  onSend: (message: { content: string; type: MessageType; meta?: any }) => void;
}

export const Toolbox: React.FC<ToolboxProps> = ({ onSend }) => {
  const [text, setText] = useState('');
  const [mode, setMode] = useState<MessageType>('text');
  const [showExtras, setShowExtras] = useState(false);

  // Specific modals states
  const [showDraw, setShowDraw] = useState(false);
  const [lockPassword, setLockPassword] = useState('');
  const [capsuleTime, setCapsuleTime] = useState('');

  const handleSend = () => {
    if (!text.trim() && mode !== 'draw' && mode !== 'nudge') return;

    let meta = {};
    if (mode === 'lock') {
      if (!lockPassword) {
         alert("Please set a password for the locked message.");
         return;
      }
      meta = { password: lockPassword };
    } else if (mode === 'capsule') {
       // Mock 1 minute for demo if not set
       const future = new Date();
       future.setSeconds(future.getSeconds() + 30); // 30s default for demo
       meta = { unlockTime: future };
    }

    onSend({
      content: text,
      type: mode,
      meta
    });

    // Reset
    setText('');
    setMode('text');
    setLockPassword('');
    setCapsuleTime('');
  };

  const handleDrawSave = (dataUrl: string) => {
    onSend({
      content: dataUrl,
      type: 'draw'
    });
    setShowDraw(false);
  };

  const handleNudge = () => {
     onSend({ content: 'NUDGE!', type: 'nudge' });
  };

  return (
    <div className="relative p-4 bg-cyber-panel border-t border-white/5 z-20">
      {/* Mode Indicators */}
      {mode !== 'text' && (
        <div className="absolute -top-10 left-4 bg-violet-600 text-white text-xs px-3 py-1 rounded-t-lg flex items-center gap-2 shadow-lg animate-slide-up">
           <span className="uppercase font-bold">{mode} MODE ACTIVE</span>
           <button onClick={() => setMode('text')}><X size={12} /></button>
        </div>
      )}

      {/* Inputs for specific modes */}
      {mode === 'lock' && (
        <div className="mb-2">
           <input 
             type="text" 
             placeholder="Set Lock Password..." 
             className="w-full bg-slate-900 border border-violet-500 rounded px-3 py-1 text-xs text-white focus:outline-none"
             value={lockPassword}
             onChange={e => setLockPassword(e.target.value)}
           />
        </div>
      )}

      <div className="flex items-end gap-2">
        <button 
          onClick={() => setShowExtras(!showExtras)}
          className={`p-3 rounded-xl transition-all ${showExtras ? 'bg-cyan-500 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
        >
          <Gamepad2 size={20} />
        </button>

        <div className="flex-1 bg-slate-800/50 border border-slate-700 rounded-xl flex items-center pr-2 focus-within:border-cyan-500 focus-within:ring-1 focus-within:ring-cyan-500/50 transition-all">
          <input 
            type="text" 
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={mode === 'text' ? "Transmit message..." : `Type ${mode} content...`}
            className="w-full bg-transparent border-none text-white px-4 py-3 focus:outline-none placeholder-slate-500"
          />
