import { User } from '../types';

const USERS_KEY = 'commune_users_db';
const SESSION_KEY = 'commune_active_session';

// Helper to get users from LocalStorage
const getUsersDB = (): User[] => {
  const usersStr = localStorage.getItem(USERS_KEY);
  return usersStr ? JSON.parse(usersStr) : [];
};

// Helper to save users
const saveUsersDB = (users: User[]) => {
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const authService = {
  // Register a new user
  register: (username: string, email: string, password: string): { success: boolean; message: string; user?: User } => {
    const users = getUsersDB();

    if (users.some(u => u.name.toLowerCase() === username.toLowerCase())) {
      return { success: false, message: 'Username already taken.' };
    }

    if (users.some(u => u.email === email)) {
      return { success: false, message: 'Email already registered.' };
    }

    const newUser: User = {
      id: 'u_' + Date.now(),
      name: username,
      email: email,
      password: password, // In a real app, this MUST be hashed
      avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}`, // Generate random avatar
      status: 'online'
    };

    users.push(newUser);
    saveUsersDB(users);

    // Auto login after register
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));

    return { success: true, message: 'Identity created successfully.', user: newUser };
  },

  // Login existing user
  login: (usernameOrEmail: string, password: string): { success: boolean; message: string; user?: User } => {
    const users = getUsersDB();
    const user = users.find(u => 
      (u.name.toLowerCase() === usernameOrEmail.toLowerCase() || u.email === usernameOrEmail) && 
      u.password === password
    );

    if (user) {
      const safeUser = { ...user };
      localStorage.setItem(SESSION_KEY, JSON.stringify(safeUser));
      return { success: true, message: 'Access Granted.', user: safeUser };
    }

    return { success: false, message: 'Invalid credentials.' };
  },

  // Check if currently logged in
  getCurrentUser: (): User | null => {
    const sessionStr = localStorage.getItem(SESSION_KEY);
    return sessionStr ? JSON.parse(sessionStr) : null;
  },

  // Logout
  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  // Mock Forgot Password
  resetPassword: (email: string): { success: boolean; message: string } => {
    const users = getUsersDB();
    const user = users.find(u => u.email === email);

    if (user) {
      return { success: true, message: `Reset link sent to neural feed: ${email}` };
    }
    return { success: false, message: 'Identity not found.' };
  }
};

import React, { useState } from 'react';
