interface AuthProps {
  onLogin: (user: UserType) => void;
}

type AuthView = 'login' | 'signup' | 'forgot';

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [view, setView] = useState<AuthView>('login');
  const [showPassword, setShowPassword] = useState(false);

  // Form State
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // Feedback State
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const clearForm = () => {
    setError('');
    setSuccess('');
    setUsername('');
    setEmail('');
    setPassword('');
  };

  const handleSwitchView = (newView: AuthView) => {
    clearForm();
    setView(newView);
  };

  const handleSubmit = async () => {
    setError('');
    setSuccess('');
    setIsLoading(true);

    // Simulate network delay for effect
    await new Promise(resolve => setTimeout(resolve, 800));

    try {
      if (view === 'login') {
        if (!username || !password) {
          setError('Credentials required.');
          setIsLoading(false);
          return;
        }
        const result = authService.login(username, password);
        if (result.success && result.user) {
          onLogin(result.user);
        } else {
          setError(result.message);
        }
      } 
      else if (view === 'signup') {
        if (!username || !email || !password) {
          setError('All fields required for initialization.');
          setIsLoading(false);
          return;
        }
        const result = authService.register(username, email, password);
        if (result.success && result.user) {
          setSuccess(result.message);
          setTimeout(() => onLogin(result.user!), 1000);
        } else {
          setError(result.message);
        }
      }
      else if (view === 'forgot') {
        if (!email) {
          setError('Target email required.');
          setIsLoading(false);
          return;
        }
        const result = authService.resetPassword(email);
        if (result.success) {
          setSuccess(result.message);
          setTimeout(() => handleSwitchView('login'), 3000);
        } else {
          setError(result.message);
        }
      }
    } catch (e) {
      setError('System Failure.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[url('https://images.unsplash.com/photo-1535868463750-c78d9543614f?q=80&w=2076&auto=format&fit=crop')] bg-cover bg-center relative">
