import React, { useState, useEffect } from 'react';
import { Auth } from './components/Auth';
import { Sidebar } from './components/Sidebar';
import { ChatArea } from './components/ChatArea';
import { FriendDiscovery } from './components/FriendDiscovery';
import { EmailVerification } from './components/EmailVerification';
import { MOCK_SESSIONS } from './constants';
import { ChatSession, Message, User } from './types';
import { authService, mapFirebaseUser } from './services/authService';
import { auth } from './firebaseConfig';
import { onAuthStateChanged } from "firebase/auth";

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>(MOCK_SESSIONS);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'chats' | 'discovery' | 'settings'>('chats');

  // Responsive check
  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Real-time Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        const user = mapFirebaseUser(firebaseUser);
        setCurrentUser(user);
      } else {
        setCurrentUser(null);
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogin = (user: User) => {
    // handled by onAuthStateChanged
  };

  const handleLogout = () => {
    authService.logout();
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  const handleSendMessage = (sessionId: string, messageData: Partial<Message>) => {
    if (!currentUser) return;

    setSessions(prev => prev.map(session => {
      if (session.id === sessionId) {
        const newMessage: Message = {
          id: Date.now().toString(),
          senderId: messageData.senderId || currentUser.id,
          content: messageData.content || '',
          type: messageData.type || 'text',
          timestamp: new Date(),
          meta: messageData.meta
        };
        return {
          ...session,
          messages: [...session.messages, newMessage],
          lastMessage: newMessage
        };
      }
      return session;
    }));
  };

  const handleSessionSelect = (id: string) => {
    setActiveSessionId(id);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  if (isLoading) {
     return <div className="h-screen bg-cyber-dark flex items-center justify-center text-cyan-400 animate-pulse">Initializing System...</div>;
  }

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  // Check Email Verification (Except for Google Providers which are usually pre-verified, but Firebase handles the boolean)
  if (!currentUser.emailVerified) {
    return <EmailVerification user={currentUser} />;
  }

  return (
    <div className="flex h-screen bg-cyber-dark text-white overflow-hidden">
      {/* Sidebar - Hidden on mobile if chat is open */}
      <div className={`${isMobileChatOpen ? 'hidden' : 'block'} md:block w-full md:w-auto h-full z-20`}>
         <Sidebar 
            currentUser={currentUser} 
            sessions={sessions} 
            activeSessionId={activeSessionId}
            onSelectSession={handleSessionSelect}
            onLogout={handleLogout}
            onViewChange={setCurrentView}
            currentView={currentView}
         />
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 h-full relative flex flex-col ${!isMobileChatOpen && 'hidden md:flex'}`}>
        {currentView === 'discovery' && !isMobileChatOpen ? (
          <FriendDiscovery />
        ) : currentView === 'settings' && !isMobileChatOpen ? (
          <div className="flex items-center justify-center h-full text-slate-500 flex-col gap-4">
             <div className="p-8 border border-white/10 rounded-xl bg-slate-900/50">
                <h2 className="text-xl font-bold mb-2">User Profile</h2>
                <div className="flex flex-col items-center mb-4">
                  <img src={currentUser.avatar} alt="Profile" className="w-20 h-20 rounded-full border-2 border-cyan-400 mb-2"/>
                  <span className="text-green-400 text-xs border border-green-500/50 px-2 py-0.5 rounded-full">Connected</span>
                </div>
                <div className="space-y-2 text-sm">
                  <p>ID: <span className="text-slate-400 font-mono text-xs">{currentUser.id}</span></p>
                  <p>Name: <span className="text-cyan-400">{currentUser.name}</span></p>
                  <p>Email: <span className="text-violet-400">{currentUser.email || 'N/A'}</span></p>
                </div>
             </div>
          </div>
        ) : (
          <ChatArea 
            session={activeSession} 
            currentUser={currentUser}
            onSendMessage={handleSendMessage}
            onBack={() => setIsMobileChatOpen(false)}
            isMobile={true}
          />
        )}
      </div>
    </div>
  );
}

export default App;

