          </div>
        </div>

        <h1 className="text-2xl font-bold text-white mb-2 tracking-widest">VERIFICATION REQUIRED</h1>
        <p className="text-slate-400 text-sm mb-6">
          Neural link established, but security protocols are pending. 
          A verification signal has been sent to <span className="text-cyan-400">{user.email}</span>.
        </p>

        {/* Status Messages */}
        {resendStatus && (
          <div className="mb-4 p-2 bg-cyan-500/10 border border-cyan-500/30 text-cyan-300 text-xs rounded">
            {resendStatus}
          </div>
        )}

        {checkMessage && (
          <div className={`mb-4 p-2 border text-xs rounded flex items-center justify-center gap-2 ${
            checkMessage.type === 'success' 
              ? 'bg-green-500/10 border-green-500/30 text-green-300' 
              : 'bg-red-500/10 border-red-500/30 text-red-300'
          }`}>
            {checkMessage.type === 'success' ? <CheckCircle2 size={14} /> : <XCircle size={14} />}
            {checkMessage.text}
          </div>
        )}

        <div className="space-y-3">
          <button 
            onClick={handleRefreshCheck}
            disabled={isChecking}
            className={`w-full bg-gradient-to-r from-violet-600 to-cyan-600 hover:from-violet-500 hover:to-cyan-500 text-white font-bold py-3 rounded-lg shadow-lg transition-all flex items-center justify-center gap-2 ${isChecking ? 'opacity-75 cursor-wait' : ''}`}
          >
            <span>{isChecking ? 'SYNCING...' : 'I HAVE VERIFIED'}</span>
            <RefreshCw size={16} className={isChecking ? 'animate-spin' : ''} />
          </button>

          <button 
            onClick={handleResend}
            disabled={isLoading || isChecking}
            className="w-full bg-slate-800/50 hover:bg-slate-700 border border-slate-600 text-slate-300 py-2 rounded-lg transition-all flex items-center justify-center gap-2 text-sm"
          >
