// Helper to map Firebase User to our App User
export const mapFirebaseUser = (fbUser: FirebaseUser): User => {
  return {
    id: fbUser.uid,
    name: fbUser.displayName || fbUser.email?.split('@')[0] || 'Anonymous',
    email: fbUser.email || undefined,
    emailVerified: fbUser.emailVerified,
    avatar: fbUser.photoURL || `https://api.dicebear.com/7.x/avataaars/svg?seed=${fbUser.uid}`,
    status: 'online'
  };
};

export const authService = {
  // Register a new user
  register: async (username: string, email: string, password: string): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);

      const photoURL = `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}`;

      // Update display name and avatar immediately in Auth
      await updateProfile(userCredential.user, {
        displayName: username,
        photoURL: photoURL
      });

      // SAVE TO FIRESTORE DATABASE
      const mappedUser = mapFirebaseUser(userCredential.user);
      // Explicitly set the name/photo we just generated, as mappedUser might not have caught the update yet
      mappedUser.name = username; 
      mappedUser.avatar = photoURL;

      await setDoc(doc(db, "users", userCredential.user.uid), {
        id: mappedUser.id,
        name: mappedUser.name,
        email: mappedUser.email,
        avatar: mappedUser.avatar,
        status: 'online',
        createdAt: serverTimestamp(),
        searchKey: username.toLowerCase() // Helper for search
      });

      // Send Verification Email
      await sendEmailVerification(userCredential.user);

      return { 
        success: true, 
        message: 'Identity created. Verification signal sent to email.', 
        user: mappedUser
      };
    } catch (error: any) {
      console.error("Registration Error:", error); 

      let msg = "Registration failed.";
      if (error.code === 'auth/email-already-in-use') msg = "Email already in use.";
      if (error.code === 'auth/weak-password') msg = "Password is too weak (min 6 chars).";
      if (error.code === 'auth/operation-not-allowed') msg = "Email/Password login is NOT enabled in Firebase Console.";

      return { success: false, message: msg };
    }
  },

  // Login existing user
  login: async (email: string, password: string): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      return { 
        success: true, 
        message: 'Access Granted.', 
        user: mapFirebaseUser(userCredential.user) 
      };
    } catch (error: any) {
      console.error("Login Error:", error); 

      let msg = "Invalid credentials.";
      if (error.code === 'auth/user-not-found' || error.code === 'auth/invalid-credential') msg = "Identity not found or password incorrect.";
      if (error.code === 'auth/wrong-password') msg = "Incorrect passcode.";
      if (error.code === 'auth/operation-not-allowed') msg = "Email/Password login is NOT enabled in Firebase Console.";

      return { success: false, message: msg };
    }
  },

  // Google Login
  loginWithGoogle: async (): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const provider = new GoogleAuthProvider();
      const result = await signInWithPopup(auth, provider);
      const user = result.user;

      // Check if user exists in DB, if not create
      const userDoc = await getDoc(doc(db, "users", user.uid));
      if (!userDoc.exists()) {
         await setDoc(doc(db, "users", user.uid), {
          id: user.uid,
          name: user.displayName || 'Anonymous',
          email: user.email,
          avatar: user.photoURL,
          status: 'online',
          createdAt: serverTimestamp(),
          searchKey: (user.displayName || '').toLowerCase()
        });
      }

      return {
        success: true,
        message: 'Google Link Established.',
        user: mapFirebaseUser(user)
      };
    } catch (error: any) {
      console.error("Google Login Error:", error);
      let msg = "Google Sign-In failed.";

      if (error.code === 'auth/popup-closed-by-user') msg = "Operation cancelled by user.";
      if (error.code === 'auth/popup-blocked') msg = "Popup blocked by browser.";
      if (error.code === 'auth/unauthorized-domain') {
        msg = `Domain Unauthorized. Add '${window.location.hostname}' to Firebase Console > Authentication > Settings > Authorized domains.`;
      }

      return { success: false, message: msg };
    }
  },

  // Resend Verification
  resendVerification: async (): Promise<{ success: boolean; message: string }> => {
    try {
      if (auth.currentUser) {
        await sendEmailVerification(auth.currentUser);
        return { success: true, message: 'Verification link re-transmitted.' };
      }
      return { success: false, message: 'No active session found.' };
    } catch (error) {
       console.error("Resend Error", error);
       return { success: false, message: 'Failed to resend link. Wait a moment.' };
    }
  },

  // Logout
  logout: async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Logout error", error);
    }
  },

  // Forgot Password
  resetPassword: async (email: string): Promise<{ success: boolean; message: string }> => {
    try {
      await sendPasswordResetEmail(auth, email);
      return { success: true, message: `Reset link sent to neural feed: ${email}` };
    } catch (error: any) {
      console.error("Reset Password Error:", error);
      return { success: false, message: 'Failed to send reset link. Check email.' };
    }
  }
};

import React, { useEffect, useState } from 'react';
import { Search, MapPin, UserPlus, RefreshCw } from 'lucide-react';
import { collection, getDocs, query, limit } from 'firebase/firestore';
import { db, auth } from '../firebaseConfig';
import { User } from '../types';

interface FriendDiscoveryProps {
  onStartChat?: (user: User) => void;
}

export const FriendDiscovery: React.FC<FriendDiscoveryProps> = ({ onStartChat }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const q = query(collection(db, "users"), limit(20));
      const querySnapshot = await getDocs(q);
      const fetchedUsers: User[] = [];

      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        // Don't show current user
        if (auth.currentUser?.uid !== userData.id) {
            fetchedUsers.push(userData);
        }
      });
      setUsers(fetchedUsers);
    } catch (error) {
      console.error("Error fetching users:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  return (
    <div className="flex-1 bg-cyber-dark overflow-y-auto p-6 animate-fade-in relative">
       <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-violet-500">
            GLOBAL FREQUENCY SCAN
          </h2>
          <button 
            onClick={fetchUsers} 
            className="p-2 bg-slate-800 rounded-lg hover:text-cyan-400 transition-colors"
