import React, { useState, useEffect } from 'react';
import { Auth } from './components/Auth';
import { Sidebar } from './components/Sidebar';
import { ChatArea } from './components/ChatArea';
import { FriendDiscovery } from './components/FriendDiscovery';
import { EmailVerification } from './components/EmailVerification';
import { MOCK_SESSIONS } from './constants';
import { ChatSession, Message, User } from './types';
import { authService, mapFirebaseUser } from './services/authService';
import { auth } from './firebaseConfig';
import { onAuthStateChanged } from "firebase/auth";

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>(MOCK_SESSIONS);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'chats' | 'discovery' | 'settings'>('chats');

  // Responsive check
  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Real-time Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        const user = mapFirebaseUser(firebaseUser);
        setCurrentUser(user);
      } else {
        setCurrentUser(null);
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogin = (user: User) => {
    // handled by onAuthStateChanged
  };

  const handleLogout = () => {
    authService.logout();
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
  };

  // Logic to manually check verification status without page reload
  const handleVerificationCheck = async (): Promise<boolean> => {
    if (auth.currentUser) {
      try {
        await auth.currentUser.reload(); // Fetch fresh data from Firebase
        const refreshedUser = mapFirebaseUser(auth.currentUser);
        setCurrentUser(refreshedUser); // Update local state to trigger re-render
        return refreshedUser.emailVerified || false;
      } catch (e) {
        console.error("Verification check failed", e);
        return false;
      }
    }
    return false;
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  const handleSendMessage = (sessionId: string, messageData: Partial<Message>) => {
    if (!currentUser) return;

    setSessions(prev => prev.map(session => {
      if (session.id === sessionId) {
        const newMessage: Message = {
          id: Date.now().toString(),
          senderId: messageData.senderId || currentUser.id,
          content: messageData.content || '',
          type: messageData.type || 'text',
          timestamp: new Date(),
          meta: messageData.meta
        };
        return {
          ...session,
          messages: [...session.messages, newMessage],
          lastMessage: newMessage
        };
      }
      return session;
    }));
  };

  const handleSessionSelect = (id: string) => {
    setActiveSessionId(id);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  const handleStartChat = (targetUser: User) => {
    // Check if session already exists
    const existingSession = sessions.find(s => 
      s.participants.some(p => p.id === targetUser.id)
    );

    if (existingSession) {
      setActiveSessionId(existingSession.id);
    } else {
      // Create temporary local session (In real app, create in DB)
      const newSession: ChatSession = {
        id: `temp_${Date.now()}`,
        participants: [currentUser!, targetUser],
        messages: [],
        unreadCount: 0
      };
      setSessions([newSession, ...sessions]);
      setActiveSessionId(newSession.id);
    }

    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  if (isLoading) {
     return <div className="h-screen bg-cyber-dark flex items-center justify-center text-cyan-400 animate-pulse">Initializing System...</div>;
  }

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  // Check Email Verification
  if (!currentUser.emailVerified) {
    return <EmailVerification user={currentUser} onCheckVerification={handleVerificationCheck} />;
  }

  return (
    <div className="flex h-screen bg-cyber-dark text-white overflow-hidden">
      {/* Sidebar - Hidden on mobile if chat is open */}
      <div className={`${isMobileChatOpen ? 'hidden' : 'block'} md:block w-full md:w-auto h-full z-20`}>
         <Sidebar 
            currentUser={currentUser} 
            sessions={sessions} 
            activeSessionId={activeSessionId}
            onSelectSession={handleSessionSelect}
            onLogout={handleLogout}
            onViewChange={setCurrentView}
            currentView={currentView}
         />
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 h-full relative flex flex-col ${!isMobileChatOpen && 'hidden md:flex'}`}>
        {currentView === 'discovery' && !isMobileChatOpen ? (
          <FriendDiscovery onStartChat={handleStartChat} />
        ) : currentView === 'settings' && !isMobileChatOpen ? (
          <div className="flex items-center justify-center h-full text-slate-500 flex-col gap-4">
             <div className="p-8 border border-white/10 rounded-xl bg-slate-900/50">
                <h2 className="text-xl font-bold mb-2">User Profile</h2>
                <div className="flex flex-col items-center mb-4">
                  <img src={currentUser.avatar} alt="Profile" className="w-20 h-20 rounded-full border-2 border-cyan-400 mb-2"/>
                  <span className="text-green-400 text-xs border border-green-500/50 px-2 py-0.5 rounded-full">Connected</span>
                </div>
                <div className="space-y-2 text-sm">
                  <p>ID: <span className="text-slate-400 font-mono text-xs">{currentUser.id}</span></p>
                  <p>Name: <span className="text-cyan-400">{currentUser.name}</span></p>
                  <p>Email: <span className="text-violet-400">{currentUser.email || 'N/A'}</span></p>
                </div>
             </div>
          </div>
        ) : (
          <ChatArea 
            session={activeSession} 
            currentUser={currentUser}
            onSendMessage={handleSendMessage}
            onBack={() => setIsMobileChatOpen(false)}
            isMobile={true}
          />
        )}
      </div>
    </div>
  );
}

export default App;

import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut, 
  updateProfile,
  sendPasswordResetEmail,
  sendEmailVerification,
  signInWithPopup,
  GoogleAuthProvider,
  User as FirebaseUser
} from "firebase/auth";
import { doc, setDoc, getDoc, serverTimestamp } from "firebase/firestore";
import { auth, db } from "../firebaseConfig";
import { User } from '../types';

// Helper to map Firebase User to our App User
export const mapFirebaseUser = (fbUser: FirebaseUser): User => {
  return {
    id: fbUser.uid,
    name: fbUser.displayName || fbUser.email?.split('@')[0] || 'Anonymous',
    email: fbUser.email || undefined,
    emailVerified: fbUser.emailVerified,
    avatar: fbUser.photoURL || `https://api.dicebear.com/7.x/avataaars/svg?seed=${fbUser.uid}`,
    status: 'online'
  };
};

export const authService = {
  // Register a new user
  register: async (username: string, email: string, password: string): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);

      const photoURL = `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}`;

      // Update display name and avatar immediately in Auth
      await updateProfile(userCredential.user, {
        displayName: username,
        photoURL: photoURL
      });

      // SAVE TO FIRESTORE DATABASE
      const mappedUser = mapFirebaseUser(userCredential.user);
      // Explicitly set the name/photo we just generated, as mappedUser might not have caught the update yet
      mappedUser.name = username; 
      mappedUser.avatar = photoURL;

      await setDoc(doc(db, "users", userCredential.user.uid), {
        id: mappedUser.id,
        name: mappedUser.name,
        email: mappedUser.email,
        avatar: mappedUser.avatar,
        status: 'online',
        createdAt: serverTimestamp(),
        searchKey: username.toLowerCase() // Helper for search
      });

      // Send Verification Email
      await sendEmailVerification(userCredential.user);

      return { 
        success: true, 
        message: 'Identity created. Verification signal sent to email.', 
        user: mappedUser
      };
    } catch (error: any) {
      let msg = "Registration failed.";

      // Handle known errors gracefully without spamming console
      if (error.code === 'auth/email-already-in-use') {
        msg = "Account already exists for this email. Please log in.";
      } else if (error.code === 'auth/weak-password') {
        msg = "Password is too weak (min 6 chars).";
      } else {
        // Only log unknown errors
        console.error("Registration Error:", error); 
        if (error.code === 'auth/operation-not-allowed') msg = "Email/Password login is NOT enabled in Firebase Console.";
      }

      return { success: false, message: msg };
    }
  },

  // Login existing user
  login: async (email: string, password: string): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      return { 
        success: true, 
        message: 'Access Granted.', 
        user: mapFirebaseUser(userCredential.user) 
      };
    } catch (error: any) {
      let msg = "Invalid credentials.";

      if (error.code === 'auth/user-not-found' || error.code === 'auth/invalid-credential') {
        msg = "Identity not found or password incorrect.";
      } else if (error.code === 'auth/wrong-password') {
        msg = "Incorrect passcode.";
      } else {
        console.error("Login Error:", error);
        if (error.code === 'auth/operation-not-allowed') msg = "Email/Password login is NOT enabled in Firebase Console.";
      }

      return { success: false, message: msg };
    }
  },

  // Google Login
  loginWithGoogle: async (): Promise<{ success: boolean; message: string; user?: User }> => {
    try {
      const provider = new GoogleAuthProvider();
      const result = await signInWithPopup(auth, provider);
      const user = result.user;

      // Check if user exists in DB, if not create
      const userDoc = await getDoc(doc(db, "users", user.uid));
      if (!userDoc.exists()) {
         await setDoc(doc(db, "users", user.uid), {
          id: user.uid,
          name: user.displayName || 'Anonymous',
          email: user.email,
          avatar: user.photoURL,
          status: 'online',
          createdAt: serverTimestamp(),
          searchKey: (user.displayName || '').toLowerCase()
        });
      }

      return {
        success: true,
        message: 'Google Link Established.',
        user: mapFirebaseUser(user)
      };
    } catch (error: any) {
      console.error("Google Login Error:", error);
      let msg = "Google Sign-In failed.";

      if (error.code === 'auth/popup-closed-by-user') msg = "Operation cancelled by user.";
      if (error.code === 'auth/popup-blocked') msg = "Popup blocked by browser.";
      if (error.code === 'auth/unauthorized-domain') {
        msg = `Domain Unauthorized. Add '${window.location.hostname}' to Firebase Console > Authentication > Settings > Authorized domains.`;
      }

      return { success: false, message: msg };
    }
  },

  // Resend Verification
  resendVerification: async (): Promise<{ success: boolean; message: string }> => {
    try {
      if (auth.currentUser) {
        await sendEmailVerification(auth.currentUser);
        return { success: true, message: 'Verification link re-transmitted.' };
      }
      return { success: false, message: 'No active session found.' };
    } catch (error) {
       console.error("Resend Error", error);
       return { success: false, message: 'Failed to resend link. Wait a moment.' };
    }
  },

  // Logout
  logout: async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Logout error", error);
    }
  },

  // Forgot Password
  resetPassword: async (email: string): Promise<{ success: boolean; message: string }> => {
    try {
      await sendPasswordResetEmail(auth, email);
      return { success: true, message: `Reset link sent to neural feed: ${email}` };
    } catch (error: any) {
      console.error("Reset Password Error:", error);
      return { success: false, message: 'Failed to send reset link. Check email.' };
    }
  }
};

