import { collection, getDocs, query, limit } from 'firebase/firestore';
import { db, auth } from '../firebaseConfig';
import { User } from '../types';

interface FriendDiscoveryProps {
  onStartChat?: (user: User) => void;
}

// Fallback data in case database is not enabled
const FALLBACK_USERS: User[] = [
  { id: 'mock1', name: 'Neon_Drifter', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=neon', status: 'online' },
  { id: 'mock2', name: 'Cyber_Vixen', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=vixen', status: 'busy' },
  { id: 'mock3', name: 'Glitch_007', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=glitch', status: 'online' },
  { id: 'mock4', name: 'Net_Runner', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=runner', status: 'offline' },
  { id: 'mock5', name: 'Data_Ghost', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=ghost', status: 'busy' },
];

export const FriendDiscovery: React.FC<FriendDiscoveryProps> = ({ onStartChat }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isOfflineMode, setIsOfflineMode] = useState(false);

  const fetchUsers = async () => {
    setLoading(true);
    setIsOfflineMode(false);
    try {
      const q = query(collection(db, "users"), limit(20));
      const querySnapshot = await getDocs(q);
      const fetchedUsers: User[] = [];

      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        if (auth.currentUser?.uid !== userData.id) {
            fetchedUsers.push(userData);
        }
      });

      if (fetchedUsers.length === 0) {
        // If DB is empty, show mocks just for demo
        setUsers(FALLBACK_USERS);
      } else {
        setUsers(fetchedUsers);
      }
    } catch (error) {
      console.warn("Firestore access failed, switching to offline simulation:", error);
      setUsers(FALLBACK_USERS);
      setIsOfflineMode(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  return (
    <div className="flex-1 bg-cyber-dark overflow-y-auto p-6 animate-fade-in relative">
       <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-violet-500">
            GLOBAL FREQUENCY SCAN
          </h2>
          <div className="flex gap-2">
            {isOfflineMode && <span className="text-yellow-500 text-xs flex items-center gap-1 border border-yellow-500/30 px-2 rounded bg-yellow-500/10"><WifiOff size={12}/> OFFLINE SIMULATION</span>}
            <button 
                onClick={fetchUsers} 
                className="p-2 bg-slate-800 rounded-lg hover:text-cyan-400 transition-colors"
            >
                <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
            </button>
          </div>
       </div>

       <div className="relative mb-8 h-48 rounded-2xl overflow-hidden border border-cyan-500/30 group">
         <img src="https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=2072&auto=format&fit=crop" className="w-full h-full object-cover opacity-60 group-hover:scale-110 transition-transform duration-700" alt="Map" />
         <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent"></div>
