export type MessageType = 'text' | 'stealth' | 'scratch' | 'capsule' | 'lock' | 'nudge' | 'draw' | 'image' | 'voice';

export interface User {
  id: string;
  name: string;
  avatar: string;
  status: 'online' | 'offline' | 'busy';
  isAi?: boolean;
  email?: string; 
  emailVerified?: boolean;
  bio?: string;      // Added
  gender?: string;   // Added
}

export interface Message {
  id: string;
  senderId: string;
  content: string; 
  type: MessageType;
  timestamp: Date;
  meta?: {
    unlockTime?: Date;
    password?: string;
    isOpened?: boolean; 
