import { doc, updateDoc, collection, getDocs, query, limit, where } from "firebase/firestore";
import { db, auth } from "../firebaseConfig";
import { User } from '../types';

export const dbService = {
  // Update User Profile
  updateProfile: async (userId: string, data: { name?: string; bio?: string; gender?: string; avatar?: string }) => {
    try {
      const userRef = doc(db, "users", userId);
      await updateDoc(userRef, data);
      return { success: true, message: "Profile updated successfully." };
    } catch (error) {
      console.error("Error updating profile:", error);
      return { success: false, message: "Failed to update profile." };
    }
  },

  // Get All Real Users (excluding self)
  getAllUsers: async (): Promise<User[]> => {
    try {
      const usersRef = collection(db, "users");
      const q = query(usersRef, limit(50)); // Limit to 50 for performance
      const querySnapshot = await getDocs(q);

      const users: User[] = [];
      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        // Exclude current user and ensure ID exists
        if (auth.currentUser?.uid !== userData.id && userData.id) {
          users.push(userData);
        }
      });
      return users;
    } catch (error) {
      console.error("Error fetching users:", error);
      return [];
    }
  }
};

