const CLOUD_NAME = 'doqmnlkuw';
const UPLOAD_PRESET = 'Commune Chat'; // Space is handled by FormData

export const uploadToCloudinary = async (file: File): Promise<{ url: string; type: 'image' | 'video' } | null> => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', UPLOAD_PRESET);

  try {
    const response = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/auto/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!response.ok) {
      throw new Error('Upload failed');
    }

    const data = await response.json();
    return {
      url: data.secure_url,
      type: data.resource_type === 'video' ? 'video' : 'image' // Cloudinary returns 'image' or 'video'
    };
  } catch (error) {
    console.error('Cloudinary Upload Error:', error);
    return null;
  }
};

