service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is signed in
    function isAuthenticated() {
      return request.auth != null;
    }

    // Helper function to check if the user is the owner of the document
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // USERS COLLECTION RULES
    match /users/{userId} {
      // 1. READ: Allow any authenticated user to read profiles (Required for Friend Discovery)
      allow read: if isAuthenticated();

      // 2. CREATE: Allow creating a profile only if the Doc ID matches their Auth ID
      allow create: if isOwner(userId);

      // 3. UPDATE: Allow updating only their own profile
      // Validation: Prevent changing the 'id' field to mismatch the document ID
      allow update: if isOwner(userId) 
                    && request.resource.data.id == userId;

      // 4. DELETE: Prevent users from deleting accounts directly (safety)
      allow delete: if false; 
    }

    // MESSAGES / CHATS (Future Proofing for Real-time Chat)
    // This allows users to read/write only chats they are part of
    match /chats/{chatId} {
      allow read, write: if isAuthenticated() && 
                         (resource == null || resource.data.participants.hasAny([request.auth.uid]));
    }
  }
}

export type MessageType = 'text' | 'stealth' | 'scratch' | 'capsule' | 'lock' | 'nudge' | 'draw' | 'image' | 'voice';

export interface User {
  id: string;
  name: string;
  avatar: string;
  status: 'online' | 'offline' | 'busy';
  isAi?: boolean;
  email?: string; 
  emailVerified?: boolean;
  bio?: string;
  gender?: string;
  location?: string;   // Added
  website?: string;    // Added
  birthdate?: string;  // Added
}

export interface Message {
  id: string;
  senderId: string;
  content: string; 
  type: MessageType;
  timestamp: Date;
  meta?: {
    unlockTime?: Date;
    password?: string;
    isOpened?: boolean; 
  };
}

export interface ChatSession {
  id: string;
  participants: User[]; 
  messages: Message[];
  lastMessage?: Message;
  unreadCount: number;
}

import { doc, updateDoc, collection, getDocs, query, limit, setDoc } from "firebase/firestore";
import { db, auth } from "../firebaseConfig";
import { User } from '../types';

export const dbService = {
  // Update User Profile
  updateProfile: async (userId: string, data: Partial<User>) => {
    try {
      const userRef = doc(db, "users", userId);
      // Try update first
      try {
        await updateDoc(userRef, data);
      } catch (e: any) {
        // If document doesn't exist (e.g. created during auth only), create it
        if (e.code === 'not-found' || e.message.includes('not found')) {
           await setDoc(userRef, { ...data, id: userId }, { merge: true });
        } else {
           throw e;
        }
      }
      return { success: true, message: "Profile updated successfully." };
    } catch (error) {
      console.error("Profile Update Error:", error);
      return { success: false, message: "Failed to update profile. Database unreachable." };
    }
  },

  // Get All Real Users (No Mocks)
  getAllUsers: async (): Promise<User[]> => {
    try {
      const usersRef = collection(db, "users");
      // Fetch up to 100 users for discovery
      const q = query(usersRef, limit(100));
      const querySnapshot = await getDocs(q);

      const users: User[] = [];
      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        // Exclude current user and ensure ID exists
        if (auth.currentUser?.uid !== userData.id && userData.id) {
          users.push(userData);
        }
      });

      return users;
    } catch (error) {
      console.error("Error fetching users:", error);
      return []; // Return empty array if error, no mocks
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Auth } from './components/Auth';
import { Sidebar } from './components/Sidebar';
import { ChatArea } from './components/ChatArea';
import { FriendDiscovery } from './components/FriendDiscovery';
import { Settings } from './components/Settings'; // Imported Settings
import { EmailVerification } from './components/EmailVerification';
import { ChatSession, Message, User } from './types';
import { authService, mapFirebaseUser } from './services/authService';
import { auth } from './firebaseConfig';
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore"; // Import for fetching fresh profile
import { db } from './firebaseConfig';

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>([]); // Initialized empty
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'chats' | 'discovery' | 'settings'>('chats');

  // Responsive check
  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Real-time Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        let user = mapFirebaseUser(firebaseUser);

        // Fetch extended profile data from Firestore
        try {
          const userDoc = await getDoc(doc(db, "users", user.id));
          if (userDoc.exists()) {
             const data = userDoc.data();
             user = { ...user, ...data }; // Merge all Firestore data
          }
        } catch (e) {
          console.warn("Could not fetch extended profile", e);
        }

        setCurrentUser(user);
      } else {
        setCurrentUser(null);
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogin = (user: User) => {
    // handled by onAuthStateChanged
  };

  const handleLogout = () => {
    authService.logout();
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
    setSessions([]); // Clear sessions on logout
  };

  const handleVerificationCheck = async (): Promise<boolean> => {
    if (auth.currentUser) {
      try {
        await auth.currentUser.reload(); 
        const refreshedUser = mapFirebaseUser(auth.currentUser);
        setCurrentUser(prev => prev ? { ...prev, emailVerified: refreshedUser.emailVerified } : null);
        return refreshedUser.emailVerified || false;
      } catch (e) {
        console.error("Verification check failed", e);
        return false;
      }
    }
    return false;
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  const handleSendMessage = (sessionId: string, messageData: Partial<Message>) => {
    if (!currentUser) return;

    setSessions(prev => prev.map(session => {
      if (session.id === sessionId) {
        const newMessage: Message = {
          id: Date.now().toString(),
          senderId: messageData.senderId || currentUser.id,
          content: messageData.content || '',
          type: messageData.type || 'text',
          timestamp: new Date(),
          meta: messageData.meta
        };
        return {
          ...session,
          messages: [...session.messages, newMessage],
          lastMessage: newMessage
        };
      }
      return session;
    }));
  };

  const handleSessionSelect = (id: string) => {
    setActiveSessionId(id);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  const handleStartChat = (targetUser: User) => {
    // Check if session already exists locally
    const existingSession = sessions.find(s => 
      s.participants.some(p => p.id === targetUser.id)
    );

    if (existingSession) {
      setActiveSessionId(existingSession.id);
    } else {
      const newSession: ChatSession = {
        id: `temp_${Date.now()}`,
        participants: [currentUser!, targetUser],
        messages: [],
        unreadCount: 0
      };
      setSessions([newSession, ...sessions]);
      setActiveSessionId(newSession.id);
    }

    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setCurrentUser(updatedUser);
  };

  if (isLoading) {
     return <div className="h-screen bg-cyber-dark flex items-center justify-center text-cyan-400 animate-pulse">Initializing System...</div>;
  }

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  if (!currentUser.emailVerified) {
    return <EmailVerification user={currentUser} onCheckVerification={handleVerificationCheck} />;
  }

  return (
    <div className="flex h-screen bg-cyber-dark text-white overflow-hidden">
      {/* Sidebar */}
      <div className={`${isMobileChatOpen ? 'hidden' : 'block'} md:block w-full md:w-auto h-full z-20`}>
         <Sidebar 
            currentUser={currentUser} 
            sessions={sessions} 
            activeSessionId={activeSessionId}
            onSelectSession={handleSessionSelect}
            onLogout={handleLogout}
            onViewChange={setCurrentView}
            currentView={currentView}
         />
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 h-full relative flex flex-col ${!isMobileChatOpen && 'hidden md:flex'}`}>

        {/* VIEW ROUTING LOGIC */}
        {currentView === 'discovery' && !isMobileChatOpen ? (
          <FriendDiscovery onStartChat={handleStartChat} />
        ) : currentView === 'settings' && !isMobileChatOpen ? (
          <Settings currentUser={currentUser} onUpdateUser={handleUpdateUser} />
        ) : (
          <ChatArea 
            session={activeSession} 
            currentUser={currentUser}
            onSendMessage={handleSendMessage}
            onBack={() => setIsMobileChatOpen(false)}
            isMobile={true}
          />
        )}
      </div>
    </div>
  );
}

export default App;

