                  className={`w-40 h-40 rounded-full border-4 border-slate-800 ring-2 ring-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] object-cover transition-opacity ${isUploading ? 'opacity-50' : ''}`}
