                />
             </div>
             <p className="text-xs text-slate-500 text-center">Tap image to upload new Neural Avatar</p>
          </div>

          {/* Form Section */}
          <div className="flex-1 w-full space-y-6">

            <div className="grid grid-cols-1 gap-6">
                {/* Name Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <UserIcon size={14} /> CODENAME (DISPLAY NAME)
                   </label>
                   <input 
                     type="text" 
