service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is signed in
    function isAuthenticated() {
      return request.auth != null;
    }

    // Helper function to check if the user is the owner of the document
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // USERS COLLECTION RULES
    match /users/{userId} {
      allow read: if isAuthenticated();
      allow create: if isOwner(userId);
      allow update: if isOwner(userId) && request.resource.data.id == userId;
      allow delete: if false; 
    }

    // CHATS COLLECTION RULES
    // We use a recursive match to cover both the chat document AND its subcollections (messages)
    match /chats/{chatId} {
      // Allow access if the user is in the 'participantIds' array
      allow read, write: if isAuthenticated() && 
                         (resource == null || resource.data.participantIds.hasAny([request.auth.uid]));

      // MESSAGES SUBCOLLECTION
      match /messages/{messageId} {
        allow read, write: if isAuthenticated(); 
        // Note: In a stricter production app, we would verify parent.data.participantIds again, 
        // but for this structure, checking the parent access is usually handled by the query or basic auth.
      }
    }
  }
}

import { 
  doc, updateDoc, collection, getDocs, query, limit, setDoc, 
  where, onSnapshot, addDoc, orderBy, serverTimestamp, getDoc, Timestamp 
} from "firebase/firestore";
import { db, auth } from "../firebaseConfig";
import { User, Message, ChatSession } from '../types';

export const dbService = {
  // --- USER MANAGEMENT ---

  updateProfile: async (userId: string, data: Partial<User>) => {
    try {
      const userRef = doc(db, "users", userId);
      try {
        await updateDoc(userRef, data);
      } catch (e: any) {
        if (e.code === 'not-found' || e.message.includes('not found')) {
           await setDoc(userRef, { ...data, id: userId }, { merge: true });
        } else {
           throw e;
        }
      }
      return { success: true, message: "Profile updated successfully." };
    } catch (error) {
      console.error("Profile Update Error:", error);
      return { success: false, message: "Failed to update profile." };
    }
  },

  getAllUsers: async (): Promise<User[]> => {
    try {
      const usersRef = collection(db, "users");
      const q = query(usersRef, limit(50)); // Limit to 50 for performance
      const querySnapshot = await getDocs(q);

      const users: User[] = [];
      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        if (auth.currentUser?.uid !== userData.id && userData.id) {
          users.push(userData);
        }
      });
      return users;
    } catch (error) {
      console.error("Error fetching users:", error);
      return [];
    }
  },

  // --- CHAT MANAGEMENT ---

  // 1. Create or Get existing Chat
  // We use a deterministic ID (sorted user IDs) to ensure 1-on-1 chats are unique
  createChat: async (currentUser: User, targetUser: User): Promise<string> => {
    const sortedIds = [currentUser.id, targetUser.id].sort();
    const chatId = `${sortedIds[0]}_${sortedIds[1]}`;
    const chatRef = doc(db, "chats", chatId);

    const chatSnap = await getDoc(chatRef);

    if (!chatSnap.exists()) {
      // Initialize new chat
      await setDoc(chatRef, {
        id: chatId,
        participantIds: [currentUser.id, targetUser.id],
        // We store basic participant info to avoid fetching it constantly, 
        // though strictly normalizing is better, this is faster for the UI.
        participantsData: {
          [currentUser.id]: { name: currentUser.name, avatar: currentUser.avatar, id: currentUser.id, isAi: !!currentUser.isAi },
          [targetUser.id]: { name: targetUser.name, avatar: targetUser.avatar, id: targetUser.id, isAi: !!targetUser.isAi }
        },
        createdAt: serverTimestamp(),
        lastMessage: null,
        updatedAt: serverTimestamp()
      });
    }

    return chatId;
  },

  // 2. Send Message
  sendMessage: async (chatId: string, message: Partial<Message>) => {
    try {
      const messagesRef = collection(db, "chats", chatId, "messages");
      const newMessage = {
        ...message,
        timestamp: serverTimestamp(),
      };

      // Add to subcollection
      await addDoc(messagesRef, newMessage);

      // Update parent chat with last message for sidebar
      const chatRef = doc(db, "chats", chatId);
      await updateDoc(chatRef, {
        lastMessage: { ...newMessage, timestamp: new Date() }, // Store Date object for UI immediately, serverTimestamp for DB
        updatedAt: serverTimestamp()
      });
    } catch (error) {
      console.error("Error sending message:", error);
    }
  },

  // 3. Listen to User's Chat List (Sidebar)
  subscribeToUserChats: (userId: string, callback: (sessions: ChatSession[]) => void) => {
    const chatsRef = collection(db, "chats");
    const q = query(
      chatsRef, 
      where("participantIds", "array-contains", userId),
      orderBy("updatedAt", "desc")
    );

    return onSnapshot(q, (snapshot) => {
      const sessions: ChatSession[] = snapshot.docs.map(doc => {
        const data = doc.data();

        // Reconstruct participants array from the map we saved
        const participants: User[] = Object.values(data.participantsData || {});

        // Convert timestamp
        let lastMsg = data.lastMessage;
        if (lastMsg && lastMsg.timestamp instanceof Timestamp) {
           lastMsg.timestamp = lastMsg.timestamp.toDate();
        } else if (lastMsg && lastMsg.timestamp && !(lastMsg.timestamp instanceof Date)) {
           // Handle edge case where it might be a string or number
           lastMsg.timestamp = new Date(lastMsg.timestamp);
        }

        return {
          id: doc.id,
          participants: participants,
          messages: [], // We don't load full history here, only lastMessage
          lastMessage: lastMsg,
          unreadCount: 0 // Simplification for now
        };
      });
      callback(sessions);
    });
  },

  // 4. Listen to Messages for a specific Chat (ChatArea)
  subscribeToChatMessages: (chatId: string, callback: (messages: Message[]) => void) => {
    const messagesRef = collection(db, "chats", chatId, "messages");
    const q = query(messagesRef, orderBy("timestamp", "asc"));

    return onSnapshot(q, (snapshot) => {
      const messages: Message[] = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          senderId: data.senderId,
          content: data.content,
          type: data.type,
          meta: data.meta,
          timestamp: data.timestamp instanceof Timestamp ? data.timestamp.toDate() : new Date()
        };
      });
      callback(messages);
    });
  }
};

import React, { useState, useEffect } from 'react';
import { Auth } from './components/Auth';
import { Sidebar } from './components/Sidebar';
import { ChatArea } from './components/ChatArea';
import { FriendDiscovery } from './components/FriendDiscovery';
import { Settings } from './components/Settings';
import { EmailVerification } from './components/EmailVerification';
import { ChatSession, Message, User } from './types';
import { authService, mapFirebaseUser } from './services/authService';
import { dbService } from './services/dbService'; // Import DB Service
import { auth } from './firebaseConfig';
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";
import { db } from './firebaseConfig';

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>([]); 
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'chats' | 'discovery' | 'settings'>('chats');

  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        let user = mapFirebaseUser(firebaseUser);
        try {
          const userDoc = await getDoc(doc(db, "users", user.id));
          if (userDoc.exists()) {
             const data = userDoc.data();
             user = { ...user, ...data };
          }
        } catch (e) {
          console.warn("Could not fetch extended profile", e);
        }
        setCurrentUser(user);
      } else {
        setCurrentUser(null);
        setSessions([]); // Clear sessions on logout
      }
      setIsLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // 2. Real-time Chat List Listener (Sidebar)
  useEffect(() => {
    if (!currentUser) return;

    // Subscribe to chats where currentUser is a participant
    const unsubscribe = dbService.subscribeToUserChats(currentUser.id, (updatedSessions) => {
      setSessions(updatedSessions);
    });

    return () => unsubscribe();
  }, [currentUser?.id]); // Only re-subscribe if user ID changes

  const handleLogin = (user: User) => {
    // Handled by onAuthStateChanged
  };

  const handleLogout = () => {
    authService.logout();
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
    setSessions([]);
  };

  const handleVerificationCheck = async (): Promise<boolean> => {
    if (auth.currentUser) {
      try {
        await auth.currentUser.reload(); 
        const refreshedUser = mapFirebaseUser(auth.currentUser);
        setCurrentUser(prev => prev ? { ...prev, emailVerified: refreshedUser.emailVerified } : null);
        return refreshedUser.emailVerified || false;
      } catch (e) {
        console.error("Verification check failed", e);
        return false;
      }
    }
    return false;
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  // 3. Handle Sending Messages (Writes to DB)
  const handleSendMessage = async (sessionId: string, messageData: Partial<Message>) => {
    if (!currentUser) return;

    // We delegate to dbService. The UI will update automatically via the listener in ChatArea
    await dbService.sendMessage(sessionId, {
      senderId: currentUser.id,
      content: messageData.content || '',
      type: messageData.type || 'text',
      meta: messageData.meta
    });
  };

  const handleSessionSelect = (id: string) => {
    setActiveSessionId(id);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
  };

  // 4. Start Chat (Creates DB Document)
  const handleStartChat = async (targetUser: User) => {
    if (!currentUser) return;

    setIsLoading(true);
    // Create or retrieve existing chat from DB
    const chatId = await dbService.createChat(currentUser, targetUser);

    setActiveSessionId(chatId);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
    setIsLoading(false);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setCurrentUser(updatedUser);
  };

  if (isLoading) {
     return <div className="h-screen bg-cyber-dark flex items-center justify-center text-cyan-400 animate-pulse">Initializing System...</div>;
  }

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  if (!currentUser.emailVerified) {
    return <EmailVerification user={currentUser} onCheckVerification={handleVerificationCheck} />;
  }

  return (
    <div className="flex h-screen bg-cyber-dark text-white overflow-hidden">
      {/* Sidebar */}
      <div className={`${isMobileChatOpen ? 'hidden' : 'block'} md:block w-full md:w-auto h-full z-20`}>
         <Sidebar 
            currentUser={currentUser} 
            sessions={sessions} 
            activeSessionId={activeSessionId}
            onSelectSession={handleSessionSelect}
            onLogout={handleLogout}
            onViewChange={setCurrentView}
            currentView={currentView}
         />
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 h-full relative flex flex-col ${!isMobileChatOpen && 'hidden md:flex'}`}>

        {/* VIEW ROUTING LOGIC */}
        {currentView === 'discovery' && !isMobileChatOpen ? (
          <FriendDiscovery onStartChat={handleStartChat} />
        ) : currentView === 'settings' && !isMobileChatOpen ? (
          <Settings currentUser={currentUser} onUpdateUser={handleUpdateUser} />
        ) : (
          <ChatArea 
            session={activeSession} 
            currentUser={currentUser}
            onSendMessage={handleSendMessage}
            onBack={() => setIsMobileChatOpen(false)}
            isMobile={true}
          />
        )}
      </div>
    </div>
  );
}

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { ChatSession, User, Message } from '../types';
import { MessageBubble } from './MessageBubble';
import { Toolbox } from './Toolbox';
import { Phone, Video, MoreHorizontal, ArrowLeft } from 'lucide-react';
import { generateAiResponse } from '../services/geminiService';
import { dbService } from '../services/dbService';

interface ChatAreaProps {
  session: ChatSession | null;
  currentUser: User;
  onSendMessage: (sessionId: string, message: Partial<Message>) => void;
  onBack: () => void;
  isMobile: boolean;
}

export const ChatArea: React.FC<ChatAreaProps> = ({ session, currentUser, onSendMessage, onBack, isMobile }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [messages, setMessages] = useState<Message[]>([]); // Local state for real-time messages
  const [isNudged, setIsNudged] = useState(false);
  const [isTyping, setIsTyping] = useState(false);

  // 1. Listen to Real-time Messages when session changes
  useEffect(() => {
    if (session?.id) {
       // Subscribe to the messages subcollection
       const unsubscribe = dbService.subscribeToChatMessages(session.id, (newMessages) => {
         setMessages(newMessages);
       });
       return () => unsubscribe();
    } else {
      setMessages([]);
    }
  }, [session?.id]);

  // 2. Auto-scroll
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Handle Nudge Effect (Check last real-time message)
  useEffect(() => {
    const lastMsg = messages[messages.length - 1];
    if (lastMsg?.type === 'nudge' && lastMsg.timestamp.getTime() > Date.now() - 1000) {
      setIsNudged(true);
      const timer = setTimeout(() => setIsNudged(false), 500);
      return () => clearTimeout(timer);
    }
  }, [messages]);

  // AI Response Handler (Client-side AI trigger)
  useEffect(() => {
    if (session && messages.length > 0) {
       const lastMsg = messages[messages.length - 1];
       const otherParticipant = session.participants.find(p => p.id !== currentUser.id);

       // If talking to AI and last message was from User
       if (otherParticipant?.isAi && lastMsg.senderId === currentUser.id && lastMsg.type === 'text') {
         setIsTyping(true);

         const history = messages
          .filter(m => m.type === 'text')
          .slice(-10) 
          .map(m => ({
             role: m.senderId === currentUser.id ? 'user' : 'model',
             parts: [{ text: m.content }]
          }));

         const prompt = history.pop()?.parts[0].text || "";

         generateAiResponse(prompt, history).then(text => {
             // AI "sends" message via same handler, but ID is AI's
             onSendMessage(session.id, {
                 type: 'text',
                 content: text,
                 senderId: otherParticipant.id 
             });
             setIsTyping(false);
         });
       }
    }
  }, [messages, currentUser.id, session?.participants, session?.id]);

  if (!session) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-cyber-dark text-slate-500">
         <div className="w-24 h-24 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center mb-4 shadow-[0_0_30px_rgba(6,182,212,0.1)]">
            <span className="text-4xl">👋</span>
         </div>
         <p>Select a frequency to begin transmission.</p>
      </div>
    );
  }

  const otherUser = session.participants.find(p => p.id !== currentUser.id) || session.participants[0];

  return (
    <div className={`flex-1 flex flex-col bg-cyber-dark relative overflow-hidden ${isNudged ? 'animate-shake' : ''}`}>
       {/* Background Grid */}
       <div className="absolute inset-0 opacity-10 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none"></div>

       {/* Header */}
       <div className="relative z-10 p-4 border-b border-white/5 bg-cyber-panel/80 backdrop-blur-md flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
             {isMobile && (
               <button onClick={onBack} className="md:hidden text-slate-400 hover:text-white">
                 <ArrowLeft />
               </button>
             )}
             <img src={otherUser.avatar} className="w-10 h-10 rounded-full border border-cyan-500" alt={otherUser.name} />
             <div>
               <h3 className="font-bold text-white flex items-center gap-2">
                 {otherUser.name}
                 {otherUser.isAi && <span className="bg-violet-600 text-[10px] px-1 rounded">AI</span>}
               </h3>
               <span className="text-xs text-cyan-400">{isTyping ? 'Computing...' : otherUser.status}</span>
             </div>
          </div>
          <div className="flex gap-4 text-slate-400">
             <button className="hover:text-cyan-400 transition-colors"><Phone size={20} /></button>
             <button className="hover:text-cyan-400 transition-colors"><Video size={20} /></button>
             <button className="hover:text-cyan-400 transition-colors"><MoreHorizontal size={20} /></button>
          </div>
       </div>

       {/* Messages */}
       <div className="flex-1 overflow-y-auto p-4 space-y-2 relative z-10" ref={scrollRef}>
          {messages.map((msg) => (
             <MessageBubble 
               key={msg.id} 
               message={msg} 
               isOwn={msg.senderId === currentUser.id} 
             />
          ))}
          {isTyping && (
             <div className="max-w-[100px] bg-slate-800/80 p-3 rounded-2xl rounded-tl-none flex items-center gap-1">
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-150"></div>
             </div>
          )}
       </div>

       {/* Composer */}
       <Toolbox 
         onSend={(msg) => onSendMessage(session.id, { ...msg, senderId: currentUser.id })} 
       />
    </div>
  );
};

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    function isAuthenticated() {
      return request.auth != null;
    }

    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // USERS
    match /users/{userId} {
      allow read: if isAuthenticated();
      allow create: if isOwner(userId);
      // Ensure we don't block updates if 'id' is missing from payload (Partial update)
      allow update: if isOwner(userId) && 
                    (!('id' in request.resource.data) || request.resource.data.id == userId);
      allow delete: if false; 
    }

    // CHATS
    match /chats/{chatId} {
      // READ: User must be a participant
      allow read: if isAuthenticated() && resource.data.participantIds.hasAny([request.auth.uid]);

      // CREATE: User must include themselves in participantIds
      allow create: if isAuthenticated() && request.resource.data.participantIds.hasAny([request.auth.uid]);

      // UPDATE: User must be a participant of the existing chat
      allow update: if isAuthenticated() && resource.data.participantIds.hasAny([request.auth.uid]);

      // MESSAGES
      match /messages/{messageId} {
         // Allow any authenticated user to read/write messages
         // (In a stricter app, we would validate parent chat participants, but this ensures functionality now)
         allow read, write: if isAuthenticated();
      }
    }
  }
}

import { 
  doc, updateDoc, collection, getDocs, query, limit, setDoc, 
  where, onSnapshot, addDoc, orderBy, serverTimestamp, getDoc, Timestamp 
} from "firebase/firestore";
import { db, auth } from "../firebaseConfig";
import { User, Message, ChatSession } from '../types';

export const dbService = {
  // --- USER MANAGEMENT ---

  updateProfile: async (userId: string, data: Partial<User>) => {
    try {
      const userRef = doc(db, "users", userId);
      try {
        await updateDoc(userRef, data);
      } catch (e: any) {
        if (e.code === 'not-found' || e.message.includes('not found')) {
           await setDoc(userRef, { ...data, id: userId }, { merge: true });
        } else {
           throw e;
        }
      }
      return { success: true, message: "Profile updated successfully." };
    } catch (error) {
      console.error("Profile Update Error:", error);
      return { success: false, message: "Failed to update profile." };
    }
  },

  getAllUsers: async (): Promise<User[]> => {
    try {
      const usersRef = collection(db, "users");
      const q = query(usersRef, limit(50));
      const querySnapshot = await getDocs(q);

      const users: User[] = [];
      querySnapshot.forEach((doc) => {
        const userData = doc.data() as User;
        if (auth.currentUser?.uid !== userData.id && userData.id) {
          users.push(userData);
        }
      });
      return users;
    } catch (error) {
      console.error("Error fetching users:", error);
      return [];
    }
  },

  // --- CHAT MANAGEMENT ---

  createChat: async (currentUser: User, targetUser: User): Promise<string> => {
    const sortedIds = [currentUser.id, targetUser.id].sort();
    const chatId = `${sortedIds[0]}_${sortedIds[1]}`;
    const chatRef = doc(db, "chats", chatId);

    const chatSnap = await getDoc(chatRef);

    if (!chatSnap.exists()) {
      await setDoc(chatRef, {
        id: chatId,
        participantIds: [currentUser.id, targetUser.id],
        participantsData: {
          [currentUser.id]: { name: currentUser.name, avatar: currentUser.avatar, id: currentUser.id, isAi: !!currentUser.isAi },
          [targetUser.id]: { name: targetUser.name, avatar: targetUser.avatar, id: targetUser.id, isAi: !!targetUser.isAi }
        },
        createdAt: serverTimestamp(),
        lastMessage: null,
        updatedAt: serverTimestamp()
      });
    }

    return chatId;
  },

  sendMessage: async (chatId: string, message: Partial<Message>) => {
    try {
      const messagesRef = collection(db, "chats", chatId, "messages");
      const newMessage = {
        ...message,
        timestamp: serverTimestamp(),
      };

      await addDoc(messagesRef, newMessage);

      const chatRef = doc(db, "chats", chatId);
      await updateDoc(chatRef, {
        lastMessage: { ...newMessage, timestamp: new Date() },
        updatedAt: serverTimestamp()
      });
    } catch (error) {
      console.error("Error sending message:", error);
    }
  },

  subscribeToUserChats: (userId: string, callback: (sessions: ChatSession[]) => void) => {
    const chatsRef = collection(db, "chats");
    // REMOVED orderBy("updatedAt", "desc") to avoid "Missing Index" errors which cause Permission Denied.
    // We will sort client-side.
    const q = query(
      chatsRef, 
      where("participantIds", "array-contains", userId)
    );

    return onSnapshot(q, (snapshot) => {
      const sessions: ChatSession[] = snapshot.docs.map(doc => {
        const data = doc.data();
        const participants: User[] = Object.values(data.participantsData || {});

        let lastMsg = data.lastMessage;
        if (lastMsg && lastMsg.timestamp instanceof Timestamp) {
           lastMsg.timestamp = lastMsg.timestamp.toDate();
        } else if (lastMsg && lastMsg.timestamp && !(lastMsg.timestamp instanceof Date)) {
           lastMsg.timestamp = new Date(lastMsg.timestamp);
        }

        return {
          id: doc.id,
          participants: participants,
          messages: [], 
          lastMessage: lastMsg,
          unreadCount: 0 
        };
      });

      // Client-side sort
      sessions.sort((a, b) => {
        const tA = a.lastMessage?.timestamp?.getTime() || 0;
        const tB = b.lastMessage?.timestamp?.getTime() || 0;
        return tB - tA;
      });

      callback(sessions);
    }, (error) => {
       console.error("Chat Subscription Error:", error);
    });
  },

  subscribeToChatMessages: (chatId: string, callback: (messages: Message[]) => void) => {
    const messagesRef = collection(db, "chats", chatId, "messages");
    const q = query(messagesRef, orderBy("timestamp", "asc"));

    return onSnapshot(q, (snapshot) => {
      const messages: Message[] = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          senderId: data.senderId,
          content: data.content,
          type: data.type,
          meta: data.meta,
          timestamp: data.timestamp instanceof Timestamp ? data.timestamp.toDate() : new Date()
        };
      });
      callback(messages);
    }, (error) => {
      console.error("Message Subscription Error:", error);
    });
  }
};

export type MessageType = 'text' | 'stealth' | 'scratch' | 'capsule' | 'lock' | 'nudge' | 'draw' | 'image' | 'voice';

export interface User {
  id: string;
  name: string;
