      };

      await addDoc(messagesRef, newMessage);

      const chatRef = doc(db, "chats", chatId);
      await updateDoc(chatRef, {
        lastMessage: { ...newMessage, timestamp: new Date() },
        updatedAt: serverTimestamp()
      });
    } catch (error) {
      console.error("Error sending message:", error);
    }
  },

  subscribeToUserChats: (userId: string, callback: (sessions: ChatSession[]) => void) => {
    const chatsRef = collection(db, "chats");
    const q = query(
      chatsRef, 
      where("participantIds", "array-contains", userId)
    );

    return onSnapshot(q, (snapshot) => {
      const sessions: ChatSession[] = snapshot.docs.map(doc => {
        const data = doc.data();
        const participants: User[] = Object.values(data.participantsData || {});

        let lastMsg = data.lastMessage;
        if (lastMsg && lastMsg.timestamp instanceof Timestamp) {
           lastMsg.timestamp = lastMsg.timestamp.toDate();
        } else if (lastMsg && lastMsg.timestamp && !(lastMsg.timestamp instanceof Date)) {
           lastMsg.timestamp = new Date(lastMsg.timestamp);
        }

        return {
          id: doc.id,
          participants: participants,
          messages: [], 
          lastMessage: lastMsg,
          unreadCount: 0,
          status: data.status || 'accepted', // Default backward compatibility
          initiatedBy: data.initiatedBy || ''
        };
      });

      sessions.sort((a, b) => {
        const tA = a.lastMessage?.timestamp?.getTime() || 0;
        const tB = b.lastMessage?.timestamp?.getTime() || 0;
        return tB - tA;
      });

      callback(sessions);
    }, (error) => {
       console.error("Chat Subscription Error:", error);
    });
  },

  subscribeToChatMessages: (chatId: string, callback: (messages: Message[]) => void) => {
    const messagesRef = collection(db, "chats", chatId, "messages");
    const q = query(messagesRef, orderBy("timestamp", "asc"));

    return onSnapshot(q, (snapshot) => {
      const messages: Message[] = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          senderId: data.senderId,
          content: data.content,
          type: data.type,
          meta: data.meta,
          timestamp: data.timestamp instanceof Timestamp ? data.timestamp.toDate() : new Date()
        };
      });
      callback(messages);
    }, (error) => {
      console.error("Message Subscription Error:", error);
    });
  }
};

import React, { useState, useEffect } from 'react';
import { Auth } from './components/Auth';
import { Sidebar } from './components/Sidebar';
import { ChatArea } from './components/ChatArea';
import { FriendDiscovery } from './components/FriendDiscovery';
import { Settings } from './components/Settings';
import { EmailVerification } from './components/EmailVerification';
import { ChatSession, Message, User } from './types';
import { authService, mapFirebaseUser } from './services/authService';
import { dbService } from './services/dbService'; 
import { auth } from './firebaseConfig';
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";
import { db } from './firebaseConfig';

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ChatSession[]>([]); 
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'chats' | 'discovery' | 'settings'>('chats');

  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        let user = mapFirebaseUser(firebaseUser);
        try {
          const userDoc = await getDoc(doc(db, "users", user.id));
          if (userDoc.exists()) {
             const data = userDoc.data();
             user = { ...user, ...data };
          }
        } catch (e) {
          console.warn("Could not fetch extended profile", e);
        }
        setCurrentUser(user);
      } else {
        setCurrentUser(null);
        setSessions([]); 
      }
      setIsLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // 2. Real-time Chat List Listener
  useEffect(() => {
    if (!currentUser) return;
    const unsubscribe = dbService.subscribeToUserChats(currentUser.id, (updatedSessions) => {
      setSessions(updatedSessions);
    });
    return () => unsubscribe();
  }, [currentUser?.id]);

  const handleLogin = (user: User) => {
    // Handled by onAuthStateChanged
  };

  const handleLogout = () => {
    authService.logout();
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
    setSessions([]);
  };

  const handleVerificationCheck = async (): Promise<boolean> => {
    if (auth.currentUser) {
      try {
        await auth.currentUser.reload(); 
        const refreshedUser = mapFirebaseUser(auth.currentUser);
        setCurrentUser(prev => prev ? { ...prev, emailVerified: refreshedUser.emailVerified } : null);
        return refreshedUser.emailVerified || false;
      } catch (e) {
        console.error("Verification check failed", e);
        return false;
      }
    }
    return false;
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  const handleSendMessage = async (sessionId: string, messageData: Partial<Message>) => {
    if (!currentUser) return;
    await dbService.sendMessage(sessionId, {
      senderId: currentUser.id,
      content: messageData.content || '',
      type: messageData.type || 'text',
      meta: messageData.meta
    });
  };

  const handleSessionSelect = (id: string) => {
    setActiveSessionId(id);
    setIsMobileChatOpen(true);
    // Important: Keep view as chats when selecting a session
    setCurrentView('chats');
  };

  const handleViewChange = (view: 'chats' | 'discovery' | 'settings') => {
    // FIX: Reset active session when changing views to ensure the main content switches
    setActiveSessionId(null);
    setIsMobileChatOpen(false);
    setCurrentView(view);
  };

  const handleStartChat = async (targetUser: User) => {
    if (!currentUser) return;
    setIsLoading(true);
    const chatId = await dbService.createChat(currentUser, targetUser);
    setActiveSessionId(chatId);
    setIsMobileChatOpen(true);
    setCurrentView('chats');
    setIsLoading(false);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setCurrentUser(updatedUser);
  };

  if (isLoading) {
     return <div className="h-screen bg-cyber-dark flex items-center justify-center text-cyan-400 animate-pulse">Initializing System...</div>;
  }

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  if (!currentUser.emailVerified) {
    return <EmailVerification user={currentUser} onCheckVerification={handleVerificationCheck} />;
  }

  return (
    <div className="flex h-screen bg-cyber-dark text-white overflow-hidden">
      {/* Sidebar */}
      <div className={`${isMobileChatOpen ? 'hidden' : 'block'} md:block w-full md:w-auto h-full z-20`}>
         <Sidebar 
            currentUser={currentUser} 
            sessions={sessions} 
            activeSessionId={activeSessionId}
            onSelectSession={handleSessionSelect}
            onLogout={handleLogout}
            onViewChange={handleViewChange} // Updated handler
            currentView={currentView}
         />
      </div>

      {/* Main Content Area Logic */}
      <div className={`flex-1 h-full relative flex flex-col ${!isMobileChatOpen && 'hidden md:flex'}`}>

        {/* If a session is active and view is chats, show ChatArea */}
        {currentView === 'chats' && activeSessionId ? (
          <ChatArea 
            session={activeSession} 
            currentUser={currentUser}
            onSendMessage={handleSendMessage}
            onBack={() => {
               setIsMobileChatOpen(false);
               setActiveSessionId(null); // Clear session on back
            }}
            isMobile={true}
          />
        ) : currentView === 'discovery' ? (
          <FriendDiscovery onStartChat={handleStartChat} />
        ) : currentView === 'settings' ? (
          <Settings currentUser={currentUser} onUpdateUser={handleUpdateUser} />
        ) : (
           // Default Empty State when in 'chats' but no session selected
           <div className="flex-1 flex flex-col items-center justify-center bg-cyber-dark text-slate-500">
             <div className="w-24 h-24 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center mb-4 shadow-[0_0_30px_rgba(6,182,212,0.1)]">
                <span className="text-4xl">👋</span>
             </div>
             <p>Select a frequency or scan for new signals.</p>
           </div>
        )}
      </div>
    </div>
  );
}

export default App;

