  const isActive = activeSessionId === session.id;

  return (
    <div 
      onClick={() => onSelect(session.id)}
      className={`group p-3 rounded-xl cursor-pointer transition-all border ${
        isActive 
          ? 'bg-gradient-to-r from-violet-600/20 to-cyan-600/20 border-cyan-500/30 shadow-[0_0_15px_rgba(6,182,212,0.1)]' 
          : 'bg-transparent border-transparent hover:bg-white/5'
      }`}
    >
      <div className="flex items-center gap-3">
        <div className="relative">
          <img src={participant.avatar} alt={participant.name} className="w-10 h-10 rounded-full object-cover" />
          {participant.isAi && (
            <div className="absolute -top-1 -right-1 bg-violet-600 text-white text-[8px] px-1 rounded-sm border border-slate-900">AI</div>
          )}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-baseline mb-1">
            <h4 className={`font-medium truncate ${isActive ? 'text-cyan-300' : 'text-slate-200'}`}>
              {participant.name}
            </h4>
            <span className="text-[10px] text-slate-500">
              {session.lastMessage ? new Date(session.lastMessage.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
            </span>
          </div>

          {isRequest ? (
             <p className="text-xs text-violet-400 font-bold flex items-center gap-1">
                <UserPlus size={10} /> Incoming Request
             </p>
          ) : (
             <p className="text-xs text-slate-400 truncate flex items-center gap-1">
               {session.status === 'pending' ? (
                  <span className="text-yellow-500 italic">Waiting for acceptance...</span>
               ) : (
                  <>
                    {session.lastMessage?.type === 'stealth' && <Shield size={10} className="text-violet-400" />}
                    {session.lastMessage?.type === 'image' ? 'Image Sent' : 
                    session.lastMessage?.type === 'draw' ? 'Drawing Sent' :
                    session.lastMessage?.type === 'lock' ? 'Locked Message' :
                    session.lastMessage?.content || 'New Connection'}
                  </>
               )}
             </p>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { ChatSession, User, Message } from '../types';
import { MessageBubble } from './MessageBubble';
import { Toolbox } from './Toolbox';
import { Phone, Video, MoreHorizontal, ArrowLeft, ShieldBan, CheckCircle, XCircle } from 'lucide-react';
import { generateAiResponse } from '../services/geminiService';
import { dbService } from '../services/dbService';

interface ChatAreaProps {
  session: ChatSession | null;
  currentUser: User;
  onSendMessage: (sessionId: string, message: Partial<Message>) => void;
  onBack: () => void;
  isMobile: boolean;
}

export const ChatArea: React.FC<ChatAreaProps> = ({ session, currentUser, onSendMessage, onBack, isMobile }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [messages, setMessages] = useState<Message[]>([]); 
  const [isNudged, setIsNudged] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [showMenu, setShowMenu] = useState(false);

  // 1. Listen to Real-time Messages
  useEffect(() => {
    if (session?.id) {
       const unsubscribe = dbService.subscribeToChatMessages(session.id, (newMessages) => {
         setMessages(newMessages);
       });
       return () => unsubscribe();
    } else {
      setMessages([]);
    }
  }, [session?.id]);

  // 2. Auto-scroll
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Handle Nudge
  useEffect(() => {
    const lastMsg = messages[messages.length - 1];
    if (lastMsg?.type === 'nudge' && lastMsg.timestamp.getTime() > Date.now() - 1000) {
      setIsNudged(true);
      const timer = setTimeout(() => setIsNudged(false), 500);
      return () => clearTimeout(timer);
    }
  }, [messages]);

  // AI Response Handler
  useEffect(() => {
    if (session && messages.length > 0 && session.status === 'accepted') {
       const lastMsg = messages[messages.length - 1];
       const otherParticipant = session.participants.find(p => p.id !== currentUser.id);

       if (otherParticipant?.isAi && lastMsg.senderId === currentUser.id && lastMsg.type === 'text') {
         setIsTyping(true);
         const history = messages
          .filter(m => m.type === 'text')
          .slice(-10) 
          .map(m => ({
             role: m.senderId === currentUser.id ? 'user' : 'model',
             parts: [{ text: m.content }]
          }));
         const prompt = history.pop()?.parts[0].text || "";

         generateAiResponse(prompt, history).then(text => {
             onSendMessage(session.id, {
                 type: 'text',
                 content: text,
                 senderId: otherParticipant.id 
             });
             setIsTyping(false);
         });
       }
    }
  }, [messages, currentUser.id, session?.participants, session?.id, session?.status]);

  if (!session) return null;

  const otherUser = session.participants.find(p => p.id !== currentUser.id) || session.participants[0];
  const isPending = session.status === 'pending';
  const isInitiator = session.initiatedBy === currentUser.id;
  const isBlocked = currentUser.blockedIds?.includes(otherUser.id);

  const handleBlock = async () => {
    if (confirm(`Block ${otherUser.name}? You will not receive messages from them.`)) {
        await dbService.toggleBlockUser(currentUser.id, otherUser.id, true);
        await dbService.deleteChat(session.id); // Or keep it but blocked
        onBack();
    }
  };

  const handleAccept = async () => {
     await dbService.acceptChatRequest(session.id);
  };

  const handleDecline = async () => {
     if (confirm("Decline and delete this request?")) {
        await dbService.deleteChat(session.id);
        onBack();
     }
  };

  return (
    <div className={`flex-1 flex flex-col bg-cyber-dark relative overflow-hidden ${isNudged ? 'animate-shake' : ''}`}>
       {/* Background Grid */}
       <div className="absolute inset-0 opacity-10 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none"></div>

       {/* Header */}
       <div className="relative z-10 p-4 border-b border-white/5 bg-cyber-panel/80 backdrop-blur-md flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
             {isMobile && (
               <button onClick={onBack} className="md:hidden text-slate-400 hover:text-white">
                 <ArrowLeft />
               </button>
             )}
             <img src={otherUser.avatar} className="w-10 h-10 rounded-full border border-cyan-500" alt={otherUser.name} />
             <div>
               <h3 className="font-bold text-white flex items-center gap-2">
                 {otherUser.name}
                 {otherUser.isAi && <span className="bg-violet-600 text-[10px] px-1 rounded">AI</span>}
               </h3>
               <span className="text-xs text-cyan-400">
                 {isBlocked ? 'BLOCKED' : isTyping ? 'Computing...' : otherUser.status}
               </span>
             </div>
          </div>
          <div className="flex gap-4 text-slate-400 relative">
             {!isPending && !isBlocked && (
               <>
                 <button className="hover:text-cyan-400 transition-colors"><Phone size={20} /></button>
                 <button className="hover:text-cyan-400 transition-colors"><Video size={20} /></button>
               </>
             )}
             <button onClick={() => setShowMenu(!showMenu)} className="hover:text-cyan-400 transition-colors"><MoreHorizontal size={20} /></button>

             {/* Dropdown Menu */}
             {showMenu && (
               <div className="absolute top-10 right-0 bg-slate-900 border border-white/10 rounded-lg shadow-xl py-2 w-40 z-50">
                  <button 
                    onClick={handleBlock}
                    className="w-full text-left px-4 py-2 text-sm text-red-400 hover:bg-white/5 flex items-center gap-2"
                  >
                    <ShieldBan size={14} /> Block User
                  </button>
               </div>
             )}
          </div>
       </div>

       {/* Messages */}
       <div className="flex-1 overflow-y-auto p-4 space-y-2 relative z-10" ref={scrollRef}>
          {/* Request Warning */}
          {isPending && !isInitiator && (
             <div className="bg-slate-800/80 border border-violet-500/50 p-4 rounded-xl text-center mb-4">
                <p className="text-white font-bold mb-2">Incoming Neural Link Request</p>
                <p className="text-slate-400 text-xs mb-4">{otherUser.name} wants to connect with you.</p>
                <div className="flex justify-center gap-4">
                   <button onClick={handleAccept} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm">
                      <CheckCircle size={16} /> Accept
                   </button>
                   <button onClick={handleDecline} className="bg-red-600 hover:bg-red-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm">
                      <XCircle size={16} /> Decline
                   </button>
                   <button onClick={handleBlock} className="bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm">
                      <ShieldBan size={16} /> Block
                   </button>
                </div>
             </div>
          )}

          {isPending && isInitiator && (
             <div className="text-center py-10 opacity-50">
                <p className="text-slate-400">Request sent. Waiting for signal acknowledgment...</p>
             </div>
          )}

          {isBlocked && (
             <div className="text-center py-10 opacity-50">
                <ShieldBan className="mx-auto text-red-500 mb-2" size={32} />
                <p className="text-red-400 font-bold">User Blocked</p>
                <p className="text-slate-500 text-xs">Communication protocols terminated.</p>
             </div>
          )}

          {/* Regular Messages (Hide if pending incoming request) */}
          {(!isPending || isInitiator) && messages.map((msg) => (
             <MessageBubble 
               key={msg.id} 
               message={msg} 
               isOwn={msg.senderId === currentUser.id} 
             />
          ))}

          {isTyping && (
             <div className="max-w-[100px] bg-slate-800/80 p-3 rounded-2xl rounded-tl-none flex items-center gap-1">
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-150"></div>
             </div>
          )}
       </div>

       {/* Composer - Hide if blocked or pending incoming request */}
       {(!isPending || isInitiator) && !isBlocked ? (
         <Toolbox 
           onSend={(msg) => onSendMessage(session.id, { ...msg, senderId: currentUser.id })} 
         />
       ) : null}
    </div>
  );
};

