                     placeholder="e.g. Neo Tokyo, Sector 7"
                   />
                </div>

                {/* Website Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <Globe size={14} /> HYPERLINK (WEBSITE)
                   </label>
                   <input 
                     type="text" 
                     value={website}
                     onChange={(e) => setWebsite(e.target.value)}
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none focus:ring-1 focus:ring-cyan-400 transition-all placeholder-slate-600"
                     placeholder="https://..."
                   />
                </div>

                {/* Bio Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <FileText size={14} /> DATA LOG (BIO)
                   </label>
                   <textarea 
                     value={bio}
                     onChange={(e) => setBio(e.target.value)}
                     rows={4}
                     maxLength={200}
                     placeholder="Enter system description..."
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none resize-none transition-all placeholder-slate-600"
                   />
                   <p className="text-right text-xs text-slate-600">{bio.length}/200</p>
                </div>
            </div>

            {/* Save Button */}
            <div className="pt-4 flex items-center gap-4">
              <button 
                onClick={handleSave}
                disabled={isSaving}
                className="px-8 py-3 bg-gradient-to-r from-violet-600 to-cyan-600 hover:from-violet-500 hover:to-cyan-500 text-white font-bold rounded-lg shadow-[0_0_20px_rgba(139,92,246,0.3)] hover:shadow-[0_0_30px_rgba(6,182,212,0.4)] flex items-center gap-2 transition-all transform active:scale-95 disabled:opacity-50"
              >
