                   <div className="flex items-center gap-2 mb-4">
                      <span className={`text-xs px-2 py-0.5 rounded-full border border-opacity-30 bg-opacity-10 ${
                         selectedUser.status === 'online' ? 'border-green-500 text-green-400 bg-green-500' :
                         selectedUser.status === 'busy' ? 'border-red-500 text-red-400 bg-red-500' :
                         'border-slate-500 text-slate-400 bg-slate-500'
                      }`}>
                         {selectedUser.status?.toUpperCase() || 'OFFLINE'}
                      </span>
                      {selectedUser.gender && (
                        <span className="text-xs px-2 py-0.5 rounded-full border border-violet-500/30 text-violet-400 bg-violet-500/10">
                          {selectedUser.gender}
                        </span>
                      )}
                   </div>

                   <div className="w-full bg-slate-900/50 p-4 rounded-xl border border-white/5 mb-6 text-left">
                      <h4 className="text-xs font-bold text-slate-500 uppercase mb-2 flex items-center gap-1">
                        <UserIcon size={12}/> Bio Data
                      </h4>
                      <p className="text-slate-300 text-sm leading-relaxed">
                        {selectedUser.bio || "This user has not uploaded any biological data description."}
                      </p>
                   </div>

                   <button 
                     onClick={handleConnect}
                     className="w-full py-3 bg-gradient-to-r from-cyan-600 to-violet-600 hover:from-cyan-500 hover:to-violet-500 text-white font-bold rounded-xl shadow-lg transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2"
                   >
                      <UserPlus size={20} />
                      ESTABLISH CONNECTION
                   </button>
                </div>
            </div>
         </div>
       )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { User } from '../types';
import { Save, User as UserIcon, FileText, Fingerprint, Camera, Loader2, MapPin, Globe, Calendar, ArrowLeft, ShieldCheck, Lock, Activity } from 'lucide-react';
import { dbService } from '../services/dbService';
import { uploadToCloudinary } from '../services/cloudinaryService';
import { authService } from '../services/authService';

interface SettingsProps {
  currentUser: User;
  onUpdateUser: (updatedUser: User) => void;
  onBack?: () => void;
}

export const Settings: React.FC<SettingsProps> = ({ currentUser, onUpdateUser, onBack }) => {
  const [name, setName] = useState(currentUser.name);
  const [bio, setBio] = useState(currentUser.bio || '');
  const [gender, setGender] = useState(currentUser.gender || 'Not Specified');
  const [location, setLocation] = useState(currentUser.location || '');
  const [website, setWebsite] = useState(currentUser.website || '');
  const [birthdate, setBirthdate] = useState(currentUser.birthdate || '');
  const [status, setStatus] = useState<'online' | 'offline' | 'busy'>(currentUser.status || 'online');

  const [newPassword, setNewPassword] = useState('');

  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [message, setMessage] = useState('');
  const [passwordMsg, setPasswordMsg] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setMessage('');

    const result = await uploadToCloudinary(file);

    if (result && result.url) {
       const updateResult = await dbService.updateProfile(currentUser.id, { avatar: result.url });

       if (updateResult.success) {
         onUpdateUser({ ...currentUser, avatar: result.url });
         setMessage('Avatar updated via Cloud Network.');
       } else {
         setMessage('Failed to link new avatar.');
       }
    } else {
      setMessage('Upload interrupted. Signal lost.');
    }
    setIsUploading(false);
  };

  const handleSave = async () => {
    setIsSaving(true);
    setMessage('');

    const updates = { name, bio, gender, location, website, birthdate, status };
    const result = await dbService.updateProfile(currentUser.id, updates);

    if (result.success) {
      setMessage('Identity protocols updated.');
      onUpdateUser({ ...currentUser, ...updates });
    } else {
      setMessage('Update failed. Connection unstable.');
    }
    setIsSaving(false);
  };

  const handlePasswordUpdate = async () => {
    if (!newPassword) return;
    setPasswordMsg('Processing security update...');
    const result = await authService.updateUserPassword(newPassword);
    setPasswordMsg(result.message);
    setNewPassword('');
  };

  return (
    <div className="flex-1 overflow-y-auto p-6 animate-fade-in bg-cyber-dark h-full">
      <div className="max-w-3xl mx-auto space-y-8 pb-10">
        <div className="flex items-center gap-3 border-b border-white/10 pb-4 mb-6">
           {onBack && (
              <button onClick={onBack} className="md:hidden text-slate-400 hover:text-white">
                <ArrowLeft size={24} />
              </button>
           )}
           <h2 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-violet-500">
             NEURAL CONFIGURATION
           </h2>
        </div>

        <div className="flex flex-col md:flex-row gap-8 items-start">
          {/* Avatar Section */}
          <div className="flex flex-col items-center gap-4 w-full md:w-1/3">
             <div 
               className="relative group cursor-pointer"
               onClick={() => !isUploading && fileInputRef.current?.click()}
             >
                <img 
                  src={currentUser.avatar} 
                  alt="Avatar" 
                  className={`w-40 h-40 rounded-full border-4 border-slate-800 ring-2 ring-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] object-cover transition-opacity ${isUploading ? 'opacity-50' : ''}`}
                />

                {/* Upload Overlay */}
                <div className="absolute inset-0 rounded-full bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                   <Camera className="text-white w-10 h-10" />
                </div>

                {/* Loading State */}
                {isUploading && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Loader2 className="text-cyan-400 w-10 h-10 animate-spin" />
                  </div>
                )}

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleFileChange} 
                  accept="image/*" 
                  className="hidden" 
                />
             </div>
             <p className="text-xs text-slate-500 text-center">Tap image to upload new Neural Avatar</p>

             {/* Status Selector */}
             <div className="w-full mt-4">
                <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider mb-2 justify-center">
                   <Activity size={14} /> CURRENT STATUS
                </label>
                <select 
                  value={status}
                  onChange={(e) => setStatus(e.target.value as any)}
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white text-center text-sm focus:border-cyan-400 outline-none"
                >
                  <option value="online">Online</option>
                  <option value="busy">Busy / Do Not Disturb</option>
                  <option value="offline">Invisible</option>
                </select>
             </div>
          </div>

          {/* Form Section */}
          <div className="flex-1 w-full space-y-6">

            <div className="grid grid-cols-1 gap-6">
                {/* Name Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <UserIcon size={14} /> CODENAME (DISPLAY NAME)
                   </label>
                   <input 
                     type="text" 
                     value={name}
                     onChange={(e) => setName(e.target.value)}
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none focus:ring-1 focus:ring-cyan-400 transition-all placeholder-slate-600"
                     placeholder="Enter your alias"
                   />
                </div>

                {/* Grid for Gender & Birthdate */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                       <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                          <Fingerprint size={14} /> ENTITY TYPE (GENDER)
                       </label>
                       <select 
                         value={gender}
                         onChange={(e) => setGender(e.target.value)}
                         className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none transition-all"
                       >
                         <option value="Not Specified">Not Specified</option>
                         <option value="Male">Male</option>
                         <option value="Female">Female</option>
                         <option value="Non-Binary">Non-Binary</option>
                         <option value="Cybernetic">Cybernetic Organism</option>
                       </select>
                    </div>

                    <div className="space-y-2">
                       <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                          <Calendar size={14} /> INCEPTION DATE
                       </label>
                       <input 
                         type="date"
                         value={birthdate}
                         onChange={(e) => setBirthdate(e.target.value)}
                         className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none transition-all [color-scheme:dark]"
                       />
                    </div>
                </div>

                {/* Location Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <MapPin size={14} /> COORDINATES (LOCATION)
                   </label>
                   <input 
                     type="text" 
                     value={location}
                     onChange={(e) => setLocation(e.target.value)}
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none focus:ring-1 focus:ring-cyan-400 transition-all placeholder-slate-600"
                     placeholder="e.g. Neo Tokyo, Sector 7"
                   />
                </div>

                {/* Website Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <Globe size={14} /> HYPERLINK (WEBSITE)
                   </label>
                   <input 
                     type="text" 
                     value={website}
                     onChange={(e) => setWebsite(e.target.value)}
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none focus:ring-1 focus:ring-cyan-400 transition-all placeholder-slate-600"
                     placeholder="https://..."
                   />
                </div>

                {/* Bio Input */}
                <div className="space-y-2">
                   <label className="flex items-center gap-2 text-sm text-cyan-400 font-bold tracking-wider">
                      <FileText size={14} /> DATA LOG (BIO)
                   </label>
                   <textarea 
                     value={bio}
                     onChange={(e) => setBio(e.target.value)}
                     rows={4}
                     maxLength={200}
                     placeholder="Enter system description..."
                     className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-cyan-400 focus:outline-none resize-none transition-all placeholder-slate-600"
                   />
                   <p className="text-right text-xs text-slate-600">{bio.length}/200</p>
                </div>
            </div>

            {/* Save Button */}
            <div className="pt-4 flex items-center gap-4 border-b border-white/10 pb-6">
              <button 
                onClick={handleSave}
                disabled={isSaving}
                className="px-8 py-3 bg-gradient-to-r from-violet-600 to-cyan-600 hover:from-violet-500 hover:to-cyan-500 text-white font-bold rounded-lg shadow-[0_0_20px_rgba(139,92,246,0.3)] hover:shadow-[0_0_30px_rgba(6,182,212,0.4)] flex items-center gap-2 transition-all transform active:scale-95 disabled:opacity-50"
              >
                <Save size={18} />
                {isSaving ? 'UPLOADING...' : 'SAVE CONFIGURATION'}
              </button>
              {message && (
                <span className={`text-sm ${message.includes('failed') || message.includes('interrupted') ? 'text-red-400' : 'text-green-400'} animate-pulse font-medium tracking-wide`}>
                  {message}
                </span>
              )}
            </div>

            {/* Password Section */}
            <div className="pt-2">
               <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                 <ShieldCheck className="text-violet-400" /> Security Protocols
               </h3>
               <div className="flex gap-4 items-end bg-slate-900/30 p-4 rounded-xl border border-white/5">
                  <div className="flex-1 space-y-2">
                     <label className="flex items-center gap-2 text-sm text-slate-400 font-bold">
                        <Lock size={14} /> NEW PASSCODE
                     </label>
                     <input 
                       type="password"
                       value={newPassword}
                       onChange={(e) => setNewPassword(e.target.value)}
                       placeholder="Enter new secure sequence..."
                       className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-white focus:border-violet-400 focus:outline-none transition-all"
                     />
                  </div>
                  <button 
                    onClick={handlePasswordUpdate}
                    className="px-6 py-3 bg-slate-800 hover:bg-slate-700 text-white rounded-lg border border-slate-600 hover:border-violet-400 transition-all mb-[1px]"
                  >
                    UPDATE
                  </button>
               </div>
               {passwordMsg && (
                 <p className={`mt-2 text-sm ${passwordMsg.includes('failed') ? 'text-red-400' : 'text-green-400'}`}>
                   {passwordMsg}
                 </p>
               )}
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Send, EyeOff, Eraser, Clock, Lock, PenTool, Mic, Gamepad2, X, Paperclip, Smile, Loader2, HelpCircle, Check, Image as ImageIcon } from 'lucide-react';
import { MessageType } from '../types';
import { DrawModal } from './DrawModal';
import { uploadToCloudinary } from '../services/cloudinaryService';

interface ToolboxProps {
  onSend: (message: { content: string; type: MessageType; meta?: any }) => void;
}

export const Toolbox: React.FC<ToolboxProps> = ({ onSend }) => {
  const [text, setText] = useState('');
  const [mode, setMode] = useState<MessageType>('text');
  const [showExtras, setShowExtras] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Specific modals states
  const [showDraw, setShowDraw] = useState(false);
  const [lockPassword, setLockPassword] = useState('');

  // New States for Preview & Guide
  const [previewMedia, setPreviewMedia] = useState<{url: string, type: 'image' | 'video'} | null>(null);
  const [showGuide, setShowGuide] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSend = () => {
    if (!text.trim() && mode !== 'draw' && mode !== 'nudge' && mode !== 'image') return;

    let meta = {};
    if (mode === 'lock') {
      if (!lockPassword) {
         alert("Please set a password for the locked message.");
         return;
      }
      meta = { password: lockPassword };
    } else if (mode === 'capsule') {
       const future = new Date();
       future.setSeconds(future.getSeconds() + 30); 
       meta = { unlockTime: future };
    }

    onSend({
      content: text,
      type: mode,
      meta
    });

    // Reset
    setText('');
    setMode('text');
    setLockPassword('');
  };

  const handleConfirmMedia = () => {
    if (previewMedia) {
       onSend({
         content: previewMedia.url,
         type: 'image' // We generally use 'image' type for media, bubble handles video rendering by extension
       });
       setPreviewMedia(null);
    }
  };

  const handleDrawSave = (dataUrl: string) => {
    onSend({
      content: dataUrl,
      type: 'draw'
    });
    setShowDraw(false);
  };

  const handleNudge = () => {
     onSend({ content: 'NUDGE!', type: 'nudge' });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const result = await uploadToCloudinary(file);

    if (result) {
      // Instead of sending immediately, set Preview
      setPreviewMedia({
        url: result.url,
        type: result.type
      });
    } else {
      alert("Upload failed. Transmission intercepted.");
    }
    setIsUploading(false);

    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="relative p-4 bg-cyber-panel border-t border-white/5 z-20">
      {/* Mode Indicators */}
      {mode !== 'text' && (
        <div className="absolute -top-10 left-4 bg-violet-600 text-white text-xs px-3 py-1 rounded-t-lg flex items-center gap-2 shadow-lg animate-slide-up">
           <span className="uppercase font-bold">{mode} MODE ACTIVE</span>
           <button onClick={() => setMode('text')}><X size={12} /></button>
        </div>
      )}

      {/* Uploading Indicator */}
      {isUploading && (
        <div className="absolute -top-10 right-4 bg-cyan-600 text-white text-xs px-3 py-1 rounded-t-lg flex items-center gap-2 shadow-lg animate-pulse">
           <Loader2 size={12} className="animate-spin" />
           <span>UPLOADING MEDIA...</span>
        </div>
      )}

      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept="image/*,video/*"
      />

      {/* Inputs for specific modes */}
      {mode === 'lock' && (
        <div className="mb-2">
           <input 
             type="text" 
             placeholder="Set Lock Password..." 
             className="w-full bg-slate-900 border border-violet-500 rounded px-3 py-1 text-xs text-white focus:outline-none"
             value={lockPassword}
             onChange={e => setLockPassword(e.target.value)}
           />
        </div>
      )}

      <div className="flex items-end gap-2">
        <button 
          onClick={() => setShowExtras(!showExtras)}
          className={`p-3 rounded-xl transition-all ${showExtras ? 'bg-cyan-500 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
        >
          <Gamepad2 size={20} />
        </button>

        <div className="flex-1 bg-slate-800/50 border border-slate-700 rounded-xl flex items-center pr-2 focus-within:border-cyan-500 focus-within:ring-1 focus-within:ring-cyan-500/50 transition-all">
          <input 
            type="text" 
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={mode === 'text' ? "Transmit message..." : `Type ${mode} content...`}
            className="w-full bg-transparent border-none text-white px-4 py-3 focus:outline-none placeholder-slate-500"
            disabled={isUploading}
          />
          <button className="p-2 text-slate-400 hover:text-white"><Smile size={18} /></button>
          <button 
            onClick={() => !isUploading && fileInputRef.current?.click()}
            className="p-2 text-slate-400 hover:text-cyan-400 transition-colors"
            title="Attach Media"
          >
            <Paperclip size={18} />
          </button>
        </div>

        <button 
          onClick={handleSend}
          disabled={isUploading}
          className="p-3 bg-gradient-to-r from-violet-600 to-cyan-600 rounded-xl text-white shadow-lg hover:shadow-cyan-500/30 transition-all transform hover:scale-105 disabled:opacity-50"
        >
          <Send size={20} />
        </button>
      </div>

      {/* Expanded Tools */}
      {showExtras && (
        <div className="mt-4 grid grid-cols-4 sm:grid-cols-8 gap-2 animate-fade-in-up">
           <ToolButton icon={<EyeOff size={18} />} label="Stealth" active={mode === 'stealth'} onClick={() => setMode('stealth')} />
           <ToolButton icon={<Eraser size={18} />} label="Scratch" active={mode === 'scratch'} onClick={() => setMode('scratch')} />
           <ToolButton icon={<Clock size={18} />} label="Capsule" active={mode === 'capsule'} onClick={() => setMode('capsule')} />
           <ToolButton icon={<Lock size={18} />} label="Lock" active={mode === 'lock'} onClick={() => setMode('lock')} />
           <ToolButton icon={<PenTool size={18} />} label="Draw" onClick={() => setShowDraw(true)} />
           <ToolButton icon={<Mic size={18} />} label="Voice" onClick={() => alert("Voice module offline")} />
           <ToolButton icon={<div className="font-bold">!</div>} label="Nudge" onClick={handleNudge} />
           <ToolButton icon={<HelpCircle size={18} />} label="Guide" onClick={() => setShowGuide(true)} />
        </div>
      )}

      {showDraw && <DrawModal onClose={() => setShowDraw(false)} onSave={handleDrawSave} />}

      {/* Media Preview Modal */}
      {previewMedia && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
           <div className="bg-cyber-panel border border-cyan-500/30 rounded-2xl max-w-md w-full overflow-hidden shadow-2xl">
              <div className="p-4 border-b border-white/5 flex justify-between items-center">
                 <h3 className="text-white font-bold flex items-center gap-2"><ImageIcon size={18} /> Confirm Upload</h3>
                 <button onClick={() => setPreviewMedia(null)} className="text-slate-400 hover:text-white"><X size={20}/></button>
              </div>
              <div className="p-4 bg-black/50 flex justify-center">
                 {previewMedia.type === 'video' ? (
                    <video src={previewMedia.url} controls className="max-h-[300px] rounded-lg" />
                 ) : (
                    <img src={previewMedia.url} alt="Preview" className="max-h-[300px] rounded-lg object-contain" />
                 )}
              </div>
              <div className="p-4 flex gap-3">
                 <button onClick={() => setPreviewMedia(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 text-white rounded-lg">Cancel</button>
                 <button onClick={handleConfirmMedia} className="flex-1 py-3 bg-gradient-to-r from-cyan-600 to-violet-600 hover:from-cyan-500 hover:to-violet-500 text-white font-bold rounded-lg flex items-center justify-center gap-2">
                    <Send size={18} /> Send
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Feature Guide Modal */}
      {showGuide && (
         <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
            <div className="bg-cyber-panel border border-violet-500/30 rounded-2xl max-w-lg w-full overflow-hidden shadow-2xl h-[80vh] flex flex-col">
               <div className="p-5 border-b border-white/5 flex justify-between items-center bg-violet-600/10">
                  <h3 className="text-xl font-bold text-white tracking-widest flex items-center gap-2">
                     <Gamepad2 size={22} className="text-cyan-400" /> TOOLBOX GUIDE
                  </h3>
                  <button onClick={() => setShowGuide(false)} className="text-slate-400 hover:text-white"><X size={24}/></button>
               </div>

               <div className="flex-1 overflow-y-auto p-6 space-y-4">
                  <GuideItem 
                     icon={<EyeOff className="text-slate-400" />} 
                     title="Stealth Mode" 
                     desc="Send hidden messages. The recipient must hover over the shield to reveal the text."
                  />
                  <GuideItem 
                     icon={<Eraser className="text-slate-400" />} 
                     title="Scratch Card" 
                     desc="Text is covered by a scratch-off layer. Users interactively rub the screen to read it."
                  />
                  <GuideItem 
                     icon={<Clock className="text-slate-400" />} 
                     title="Time Capsule" 
                     desc="Locked message that reveals itself only after a 30-second countdown."
                  />
                  <GuideItem 
                     icon={<Lock className="text-slate-400" />} 
                     title="Encrypted Lock" 
                     desc="Protect your message with a custom password. The recipient needs the key to decrypt."
                  />
                  <GuideItem 
                     icon={<PenTool className="text-slate-400" />} 
                     title="Digital Canvas" 
                     desc="Open a drawing board to sketch diagrams or art and send them as images."
                  />
                  <GuideItem 
                     icon={<div className="font-bold text-slate-400 px-2">!</div>} 
                     title="Nudge" 
                     desc="Shake the recipient's screen to get their attention immediately."
                  />
               </div>

               <div className="p-4 border-t border-white/5 bg-slate-900/50">
                  <button onClick={() => setShowGuide(false)} className="w-full py-3 bg-violet-600 hover:bg-violet-500 text-white rounded-xl font-bold">
                     ACKNOWLEDGED
                  </button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

const ToolButton = ({ icon, label, active, onClick }: any) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${active ? 'bg-violet-600 text-white' : 'bg-slate-800/50 text-slate-400 hover:bg-slate-700 hover:text-cyan-400'}`}
  >
    <div className="mb-1">{icon}</div>
    <span className="text-[10px] uppercase tracking-wide">{label}</span>
  </button>
);

const GuideItem = ({icon, title, desc}: any) => (
   <div className="flex gap-4 p-4 bg-slate-800/50 rounded-xl border border-white/5 hover:border-cyan-500/30 transition-colors">
      <div className="mt-1 p-2 bg-slate-900 rounded-lg h-fit">{icon}</div>
      <div>
         <h4 className="text-cyan-400 font-bold mb-1">{title}</h4>
